                                        left: tabStyle.left,
                                        width: tabStyle.width,
                                        opacity: tabStyle.opacity
                                    }}
                                />

                                {tabsList.map((tab, idx) => (
                                    <button 
                                        key={tab.id} 
                                        ref={el => { tabsRef.current[idx] = el; }}
