                                                <span onClick={(e) => {e.stopPropagation(); setExportLanguage('vi');}} className={`lang-pill-btn ${exportLanguage === 'vi' ? 'bg-white text-indigo-700 shadow-sm' : 'text-indigo-200 hover:text-white'}`}>VI</span>
                                            </div>
                                        </button>
                                    </div>
                                </div>

                                <div className="flex-1 bg-white dark:bg-slate-900 rounded-2xl border border-gray-100 dark:border-slate-800 shadow-sm p-6 overflow-hidden flex flex-col relative">
                                    {!finalReportText ? (
                                        <div className="flex-1 flex flex-col items-center justify-center text-center p-8">
                                            <div className="w-20 h-20 bg-indigo-50 dark:bg-slate-800 rounded-full flex items-center justify-center mb-6">
                                                <Icon name="FileText" size={40} className="text-indigo-200 dark:text-slate-600"/>
                                            </div>
                                            <h4 className="text-lg font-bold text-slate-700 dark:text-slate-200 mb-2">Ready to Synthesize</h4>
                                            <p className="text-sm text-slate-500 max-w-md mb-6">Generate a comprehensive audit report based on {Object.keys(selectedFindings).length} identified findings and context data.</p>

                                            <button onClick={handleGenerateReport} disabled={!analysisResult || analysisResult.length === 0} className="px-8 py-3 bg-gradient-to-r from-indigo-600 to-purple-600 text-white rounded-xl font-bold text-sm shadow-xl shadow-indigo-500/30 hover:scale-105 transition-transform flex items-center gap-3 disabled:opacity-50 disabled:cursor-not-allowed">
                                                {isReportLoading ? <SparkleLoader className="text-white"/> : <Icon name="Wand2" size={18}/>}
                                                {isReportLoading ? "Synthesizing Report..." : "Generate Final Report"}
                                            </button>
                                        </div>
                                    ) : (
                                        <textarea 
                                            className="flex-1 w-full h-full bg-transparent resize-none focus:outline-none text-slate-800 dark:text-slate-200 font-mono text-sm leading-relaxed" 
                                            value={finalReportText} 
                                            onChange={(e) => setFinalReportText(e.target.value)}
                                        />
                                    )}
                                </div>
                            </div>
                        )}
                    </div>
                </div>
            </div>

            {/* MODALS */}
            <CommandPaletteModal 
                isOpen={isCmdPaletteOpen} 
                onClose={() => setIsCmdPaletteOpen(false)}
                actions={commandActions}
                onSelectAction={(item: any) => {
                    item.action();
                    setIsCmdPaletteOpen(false);
                }}
            />

            <ReleaseNotesModal isOpen={showAboutModal} onClose={() => setShowAboutModal(false)} />

            {/* Settings Modal - API Keys */}
            <Modal isOpen={showSettingsModal} title="Settings & API Keys" onClose={() => setShowSettingsModal(false)}>
                <div className="space-y-6">
                    <div>
                        <h4 className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-3">Manage API Keys</h4>
                        <div className="space-y-3">
                            {/* Key List */}
                            {apiKeys.map(profile => (
                                <div key={profile.id} className={`p-3 rounded-xl border flex items-center justify-between transition-all ${profile.id === activeKeyId ? 'bg-indigo-50 border-indigo-200 dark:bg-indigo-900/20 dark:border-indigo-800' : 'bg-white border-gray-100 dark:bg-slate-800 dark:border-slate-700'}`}>
                                    <div className="flex items-center gap-3 overflow-hidden">
                                        <div onClick={() => setActiveKeyId(profile.id)} className={`cursor-pointer w-4 h-4 rounded-full border-2 flex items-center justify-center ${profile.id === activeKeyId ? 'border-indigo-500' : 'border-gray-300 dark:border-slate-500'}`}>
                                            {profile.id === activeKeyId && <div className="w-2 h-2 rounded-full bg-indigo-500"></div>}
                                        </div>
                                        <div className="flex flex-col min-w-0">
                                            <div className="flex items-center gap-2">
                                                <span className="text-sm font-bold text-slate-700 dark:text-slate-200 truncate">{profile.label}</span>
                                                {profile.status === 'valid' && <span className="text-[9px] bg-emerald-100 text-emerald-700 px-1.5 py-0.5 rounded font-bold uppercase">Valid</span>}
                                                {profile.status === 'invalid' && <span className="text-[9px] bg-red-100 text-red-700 px-1.5 py-0.5 rounded font-bold uppercase">Invalid</span>}
                                                {profile.status === 'quota_exceeded' && <span className="text-[9px] bg-orange-100 text-orange-700 px-1.5 py-0.5 rounded font-bold uppercase">Quota</span>}
                                                {profile.status === 'checking' && <Icon name="Loader" size={10} className="animate-spin text-indigo-500"/>}
                                            </div>
                                            <span className="text-[10px] text-slate-400 font-mono truncate">
                                                {profile.key.substring(0, 8)}...{profile.key.substring(profile.key.length - 4)} • {profile.latency > 0 ? `${profile.latency}ms` : 'Unknown'}
                                            </span>
                                        </div>
                                    </div>
                                    <div className="flex items-center gap-1">
                                         <button onClick={() => handleRefreshStatus(profile.id)} className="p-2 text-slate-400 hover:text-indigo-500 hover:bg-indigo-50 dark:hover:bg-slate-700 rounded-lg transition-colors" title="Check Status">
                                            <Icon name="RefreshCw" size={14} className={profile.status === 'checking' ? 'animate-spin' : ''}/>
                                        </button>
                                        <button onClick={() => handleDeleteKey(profile.id)} className="p-2 text-slate-400 hover:text-red-500 hover:bg-red-50 dark:hover:bg-red-900/20 rounded-lg transition-colors" title="Remove Key">
                                            <Icon name="Trash2" size={14}/>
                                        </button>
                                    </div>
                                </div>
                            ))}

                            {/* Add New Key Input */}
                            <div className="p-3 bg-gray-50 dark:bg-slate-800/50 rounded-xl border border-dashed border-gray-300 dark:border-slate-700 flex flex-col gap-3">
                                <input 
                                    className="w-full bg-transparent text-xs outline-none text-slate-700 dark:text-slate-300 placeholder-gray-400 border-b border-gray-200 dark:border-slate-700 pb-2 focus:border-indigo-500 transition-colors"
                                    placeholder="Enter Google Gemini API Key (starts with AIza...)"
                                    value={newKeyInput}
                                    onChange={(e) => setNewKeyInput(e.target.value)}
                                />
                                <div className="flex gap-2">
                                    <input 
                                        className="flex-1 bg-transparent text-xs outline-none text-slate-700 dark:text-slate-300 placeholder-gray-400 border-b border-gray-200 dark:border-slate-700 pb-2 focus:border-indigo-500 transition-colors"
                                        placeholder="Label (Optional, e.g. 'Personal Key')"
                                        value={newKeyLabel}
                                        onChange={(e) => setNewKeyLabel(e.target.value)}
                                    />
                                    <button 
                                        onClick={handleAddKey} 
                                        disabled={!newKeyInput || isCheckingKey}
                                        className="px-4 py-1.5 bg-indigo-600 hover:bg-indigo-700 disabled:opacity-50 disabled:cursor-not-allowed text-white text-xs font-bold rounded-lg transition-all shadow-sm"
                                    >
                                        {isCheckingKey ? <Icon name="Loader" className="animate-spin"/> : "Add Key"}
                                    </button>
                                </div>
                            </div>
                        </div>
                    </div>

                    <div className="bg-indigo-50 dark:bg-indigo-900/20 p-4 rounded-xl flex gap-3">
                        <Icon name="Info" className="text-indigo-600 dark:text-indigo-400 shrink-0 mt-0.5" size={16}/>
                        <p className="text-xs text-indigo-800 dark:text-indigo-300 leading-relaxed">
                            <strong>Note:</strong> Multiple keys are supported for "Failover Strategy". If one key hits the rate limit (Quota Exceeded), the system automatically switches to the next available valid key to continue your audit without interruption.
                        </p>
                    </div>
                </div>
            </Modal>

            {/* Global Loading Overlay (if needed for heavy non-streaming tasks) */}
            {/* Using inline loading mostly, but if we need a blocker: */}
            {isReportLoading && <AINeuralLoader message="Synthesizing Audit Report..." />}
        </div>
    );
}

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { Icon, IconSelect, IconInput, Modal } from './UI';
import { StandardsData, AuditInfo, Clause, Group, Standard } from '../types';
import { useDebounce, copyToClipboard, cleanAndParseJSON } from '../utils';
import { AUDIT_TYPES, STANDARDS_DATA } from '../constants';
import { generateMissingDescriptions } from '../services/geminiService';

interface SidebarProps {
    isOpen: boolean;
    width: number;
    setWidth: (w: number) => void;
    standards: StandardsData;
    standardKey: string;
    setStandardKey: (k: string) => void;
    auditInfo: AuditInfo;
    setAuditInfo: (info: AuditInfo) => void;
    selectedClauses: string[];
    setSelectedClauses: React.Dispatch<React.SetStateAction<string[]>>;
    onAddNewStandard: () => void;
    onUpdateStandard: (std: Standard) => void;
    onResetStandard: (key: string) => void;
}

const Sidebar = ({ isOpen, width, setWidth, standards, standardKey, setStandardKey, auditInfo, setAuditInfo, selectedClauses, setSelectedClauses, onAddNewStandard, onUpdateStandard, onResetStandard }: SidebarProps) => {
    const sidebarRef = useRef<HTMLDivElement>(null);
    const scrollContainerRef = useRef<HTMLDivElement>(null); 
    const [isResizing, setIsResizing] = useState(false);
    const [searchQueryRaw, setSearchQueryRaw] = useState("");
    const [expandedGroups, setExpandedGroups] = useState<string[]>([]);
    const [expandedClauses, setExpandedClauses] = useState<string[]>([]);
    const [showIntegrityModal, setShowIntegrityModal] = useState(false);

    // UI State: Collapse Audit Info to save space
    // Changed to default FALSE to keep it lean on startup
    const [isInfoExpanded, setIsInfoExpanded] = useState(false);

    // UI State: Scroll-aware Header Visibility
    const [isHeaderVisible, setIsHeaderVisible] = useState(true);

    // Auto-repair states
    const [isRepairing, setIsRepairing] = useState(false);
    const [copiedClauseId, setCopiedClauseId] = useState<string | null>(null);
    const [repairStats, setRepairStats] = useState<{ fixed: number, cleaned: number } | null>(null);
    const [repairedIds, setRepairedIds] = useState<string[]>([]);

    const searchQuery = useDebounce(searchQueryRaw, 300);

    const startResizing = (e: React.MouseEvent) => {
        if ((e.target as Element).classList.contains('resize-handle')) {
            e.preventDefault();
            setIsResizing(true);
            document.body.style.cursor = 'col-resize';
            document.body.style.userSelect = 'none'; 
        }
    };

    useEffect(() => {
        const stopResizing = () => {
            if (isResizing) {
                setIsResizing(false);
                document.body.style.cursor = '';
                document.body.style.userSelect = '';

                if (sidebarRef.current) {
                    const finalWidth = parseInt(sidebarRef.current.style.width, 10);
                    if (!isNaN(finalWidth)) {
                        setWidth(finalWidth);
                    }
                }
            }
        };

        const resize = (e: MouseEvent) => {
            if (isResizing && sidebarRef.current) {
                // UPDATE: Increased minimum width to 390px (iPhone 13 ratio)
                const MIN_SIDEBAR_WIDTH = 390; 
                const MIN_MAIN_CONTENT_WIDTH = 375; 
                const MAX_SIDEBAR_LIMIT = 800;

                const maxSidebarWidth = Math.min(MAX_SIDEBAR_LIMIT, window.innerWidth - MIN_MAIN_CONTENT_WIDTH);
                const newWidth = Math.max(MIN_SIDEBAR_WIDTH, Math.min(e.clientX, maxSidebarWidth));

                sidebarRef.current.style.width = `${newWidth}px`;
            }
        };

        if (isResizing) {
            window.addEventListener('mousemove', resize);
            window.addEventListener('mouseup', stopResizing);
        }
        return () => {
            window.removeEventListener('mousemove', resize);
            window.removeEventListener('mouseup', stopResizing);
        };
    }, [isResizing, setWidth]);

    // --- AGGRESSIVE SCROLL LOGIC ---
    const handleScroll = (e: React.UIEvent<HTMLDivElement>) => {
        if (isResizing) return;

        const target = e.currentTarget;
        const scrollTop = target.scrollTop;

        const SCROLL_THRESHOLD = 50; 

        if (scrollTop > SCROLL_THRESHOLD && isHeaderVisible) {
            setIsHeaderVisible(false);
        } else if (scrollTop <= SCROLL_THRESHOLD && !isHeaderVisible) {
            setIsHeaderVisible(true);
        }
    };

    // Auto-expand Audit Details if standard changes
    useEffect(() => {
        if (scrollContainerRef.current) scrollContainerRef.current.scrollTop = 0;
    }, [standardKey]);

    // --- HEALTH CHECK LOGIC ---
    const runHealthCheck = () => {
        if (!standardKey || !standards[standardKey]) return { isHealthy: false, score: 0, integrity: [], completeness: [] };
        const data = standards[standardKey];
        const integrity: { label: string, status: 'pass' | 'fail', detail: string }[] = [];
        const completeness: { label: string, status: 'pass' | 'fail', detail: string }[] = [];

        const allClauses = data.groups.flatMap(g => g.clauses);
        const flatten = (list: Clause[]): Clause[] => {
            return list.reduce((acc, c) => {
                acc.push(c);
                if (c.subClauses) acc.push(...flatten(c.subClauses));
                return acc;
            }, [] as Clause[]);
        };
        const flatList = flatten(allClauses);

        // Integrity
        const missingDesc = flatList.filter(c => !c.description || c.description.trim().length < 2).length;
        integrity.push({ 
            label: 'Content Quality', 
            status: missingDesc === 0 ? 'pass' : 'fail', 
            detail: missingDesc === 0 ? 'Descriptions OK' : `${missingDesc} incomplete` 
        });

        const uniqueCodes = new Set(flatList.map(c => c.code));
        const duplicateCount = flatList.length - uniqueCodes.size;
        integrity.push({ 
            label: 'Data Cleanliness', 
            status: duplicateCount === 0 ? 'pass' : 'fail', 
            detail: duplicateCount === 0 ? 'Clean' : `${duplicateCount} Duplicates` 
        });

        // Completeness
        if (standardKey.includes("9001")) {
            const crucial = ['8.4', '8.6', '8.7', '7.1.4'];
            crucial.forEach(code => {
                const found = flatList.some(c => c.code === code);
                completeness.push({ 
                    label: `Clause ${code}`, 
                    status: found ? 'pass' : 'fail', 
                    detail: found ? 'Present' : 'Missing (Required)' 
                });
            });
        }

        if (standardKey.includes("27001")) {
            const annexItems = flatList.filter(c => c.code.startsWith("A."));
            const isFullSet = annexItems.length >= 90; 
            completeness.push({ 
                label: 'Annex A Controls', 
                status: isFullSet ? 'pass' : 'fail', 
                detail: isFullSet ? `${annexItems.length} Controls (OK)` : `${annexItems.length}/93 (Incomplete)` 
            });
        }

        const integrityPass = integrity.every(i => i.status === 'pass');
        const completenessPass = completeness.every(i => i.status === 'pass');
        const isHealthy = integrityPass && completenessPass;

        const totalItems = integrity.length + completeness.length;
        const passItems = integrity.filter(i => i.status === 'pass').length + completeness.filter(i => i.status === 'pass').length;
        const score = Math.round((passItems / (totalItems || 1)) * 100);

        return { isHealthy, score, integrity, completeness };
    };

    const handleAutoRepair = async () => {
        if (!standardKey || !standards[standardKey]) return;
        setIsRepairing(true);
        setRepairStats(null);
        try {
            const currentStandard = JSON.parse(JSON.stringify(standards[standardKey])) as Standard; 
            const missingClauses: {ref: Clause, code: string, title: string}[] = [];
            const fixedIds: string[] = [];
            let duplicateRemovedCount = 0;

            const findMissing = (list: Clause[]) => {
                list.forEach(c => {
                    if (!c.description || c.description.trim().length < 2) {
                        missingClauses.push({ ref: c, code: c.code, title: c.title });
                    }
                    if (c.subClauses) findMissing(c.subClauses);
                });
            };
            currentStandard.groups.forEach((g: Group) => findMissing(g.clauses));

            if (missingClauses.length > 0) {
                const targets = missingClauses.map(i => ({ code: i.code, title: i.title }));
                const jsonStr = await generateMissingDescriptions(targets);
                const descriptions = cleanAndParseJSON(jsonStr);

                if (Array.isArray(descriptions)) {
                    const descMap = descriptions.reduce((acc: any, item: any) => {
                        if(item.code && item.description) acc[item.code] = item.description;
                        return acc;
                    }, {});

                    missingClauses.forEach(item => {
                        if (descMap[item.code]) {
                            item.ref.description = descMap[item.code];
                            fixedIds.push(item.ref.id);
                        }
                    });
                } else if (descriptions && typeof descriptions === 'object') {
                    missingClauses.forEach(item => {
                        if (descriptions[item.code]) {
                            item.ref.description = descriptions[item.code];
                            fixedIds.push(item.ref.id);
                        }
                    });
                }
            }

            const cleanClauses = (clauses: Clause[]): Clause[] => {
                const seenCodes = new Set<string>();
                const unique: Clause[] = [];
                for (const c of clauses) {
                    if (!seenCodes.has(c.code)) {
                        seenCodes.add(c.code);
                        if (c.subClauses) {
                            c.subClauses = cleanClauses(c.subClauses);
                        }
                        unique.push(c);
                    } else {
                        duplicateRemovedCount++;
                    }
                }
                return unique;
            };

            currentStandard.groups.forEach(g => {
                g.clauses = cleanClauses(g.clauses);
            });

            onUpdateStandard(currentStandard);
            setRepairedIds(fixedIds);
            setRepairStats({ fixed: fixedIds.length, cleaned: duplicateRemovedCount });

        } catch (e) {
            console.error("Repair failed", e);
            alert("Failed to repair automatically.");
        } finally {
            setIsRepairing(false);
        }
    };

    const handleCopySelectedClauses = () => {
        if (!standardKey || !standards[standardKey]) return;
        const findClause = (id: string, list: Clause[]): Clause | undefined => {
            for (let c of list) { 
                if (c.id === id) return c; 
                if (c.subClauses) { 
                    const f = findClause(id, c.subClauses); 
                    if (f) return f; 
                } 
            }
        };
        const allClauses = standards[standardKey].groups.flatMap(g => g.clauses);
        const selectedData = selectedClauses
            .map(id => findClause(id, allClauses))
            .filter((c): c is Clause => !!c)
            .map(c => `[${c.code}] ${c.title}`)
            .join('\n');
        copyToClipboard(selectedData);
    };

    const handleSingleClauseCopy = (e: React.MouseEvent, c: Clause) => {
        e.stopPropagation();
        copyToClipboard(`[${c.code}] ${c.title}`);
        setCopiedClauseId(c.id);
        setTimeout(() => setCopiedClauseId(null), 1500);
    };

    const toggleClauseSelection = (clause: Clause) => {
        const getAllIds = (c: Clause): string[] => {
            let ids = [c.id];
            if (c.subClauses) c.subClauses.forEach(sub => ids.push(...getAllIds(sub)));
            return ids;
        };
        const targetIds = getAllIds(clause);
        const allSelected = targetIds.every(id => selectedClauses.includes(id));
        setSelectedClauses(prev => allSelected ? prev.filter(id => !targetIds.includes(id)) : Array.from(new Set([...prev, ...targetIds])));
    };

    const toggleGroupSelection = (group: Group) => {
        const getAllIds = (list: Clause[]): string[] => {
            let ids: string[] = [];
            list.forEach(c => {
                ids.push(c.id);
                if (c.subClauses) ids.push(...getAllIds(c.subClauses));
            });
            return ids;
        };
        const groupIds = getAllIds(group.clauses);
        const allSelected = groupIds.every(id => selectedClauses.includes(id));

        if (allSelected) {
            setSelectedClauses(prev => prev.filter(id => !groupIds.includes(id)));
        } else {
            setSelectedClauses(prev => [...new Set([...prev, ...groupIds])]);
        }
    };

    const allGroupIds = standards[standardKey]?.groups.map(g => g.id) || [];
    const areAllGroupsExpanded = allGroupIds.length > 0 && expandedGroups.length === allGroupIds.length;

    const toggleExpandAll = () => {
        if (areAllGroupsExpanded) {
            setExpandedGroups([]);
        } else {
            setExpandedGroups(allGroupIds);
        }
    };

    const toggleGroupExpand = (id: string) => setExpandedGroups(prev => prev.includes(id) ? prev.filter(x => x !== id) : [...prev, id]);
    const toggleClauseExpand = (id: string) => setExpandedClauses(prev => prev.includes(id) ? prev.filter(x => x !== id) : [...prev, id]);

    const renderClauseItem = (c: Clause, level: number = 0) => {
        const hasSubs = c.subClauses && c.subClauses.length > 0;
        const isExpanded = expandedClauses.includes(c.id) || !!searchQuery;
        const isSelected = selectedClauses.includes(c.id);
        const getChildSelectionStatus = (item: Clause): { all: boolean, some: boolean } => {
            if (!item.subClauses) return { all: selectedClauses.includes(item.id), some: selectedClauses.includes(item.id) };
            const subRes = item.subClauses.map(getChildSelectionStatus);
            const all = selectedClauses.includes(item.id) && subRes.every(r => r.all);
            const some = selectedClauses.includes(item.id) || subRes.some(r => r.some);
            return { all, some };
        };
        const selection = getChildSelectionStatus(c);
        const isCopied = copiedClauseId === c.id;
        const isRepaired = repairedIds.includes(c.id);

        return (
            <div key={c.id} className={`flex flex-col transition-all duration-300 ${level > 0 ? 'ml-4 border-l-2 dark:border-slate-800' : ''}`}>
                <div className={`group flex items-start gap-3 p-2 rounded-xl transition-all duration-200 cursor-pointer ${isSelected ? 'bg-indigo-50/80 dark:bg-indigo-900/20 translate-x-1' : isRepaired ? 'bg-emerald-50/80 dark:bg-emerald-900/20 ring-1 ring-emerald-500/30' : 'hover:bg-gray-100/50 dark:hover:bg-slate-800/50 hover:translate-x-1'}`}>
                    <button onClick={(e) => { e.stopPropagation(); toggleClauseSelection(c); }} className={`mt-1 flex-shrink-0 transition-colors duration-200 ${selection.some ? 'text-indigo-600 dark:text-indigo-400 scale-110' : 'text-gray-300 dark:text-slate-600 hover:text-gray-400'}`}>
                        {selection.all ? <Icon name="CheckSquare" size={16}/> : selection.some ? <div className="w-4 h-4 bg-indigo-500 rounded flex items-center justify-center"><div className="w-2.5 h-0.5 bg-white"></div></div> : <Icon name="Square" size={16}/>}
                    </button>
                    <div 
                        className="flex-1 min-w-0" 
                        onClick={() => hasSubs ? toggleClauseExpand(c.id) : toggleClauseSelection(c)}
                    >
                        <div className="flex items-start justify-between gap-1.5">
                            <div className="flex items-center gap-1.5 flex-wrap">
                                <span className="text-xs font-bold text-indigo-700 dark:text-indigo-400 uppercase shrink-0 bg-indigo-50 dark:bg-indigo-900/30 px-1 rounded">{c.code}</span>
                                <span className="text-sm text-slate-900 dark:text-slate-100 font-medium tracking-tight leading-tight group-hover:text-indigo-600 dark:group-hover:text-indigo-400 transition-colors">{c.title}</span>
                                {isRepaired && <span className="text-[9px] font-black bg-emerald-100 text-emerald-600 px-1.5 py-0.5 rounded-md animate-pulse">UPDATED</span>}
                            </div>
                            <div className="flex items-center gap-2">
                                <button
                                    onClick={(e) => handleSingleClauseCopy(e, c)}
                                    className={`p-1 transition-all transform duration-300 ${isCopied ? 'text-emerald-600 scale-125 opacity-100' : 'opacity-0 group-hover:opacity-100 text-gray-300 hover:text-indigo-600 dark:hover:text-indigo-400 hover:scale-110'}`}
                                    title={isCopied ? "Copied!" : "Copy Clause"}
                                >
                                    <Icon name={isCopied ? "CheckThick" : "Copy"} size={isCopied ? 20 : 14} />
                                </button>
                                {hasSubs && <Icon name="ChevronDown" size={12} className={`text-gray-400 mt-0.5 shrink-0 transition-transform duration-300 ${isExpanded ? 'rotate-180' : ''}`}/>}
                            </div>
                        </div>
                        <div className="text-xs text-slate-500 dark:text-slate-400 italic mt-1.5 leading-relaxed block w-full whitespace-normal border-t border-gray-100 dark:border-slate-800 pt-1">
                            {c.description}
                        </div>
                    </div>
                </div>
                {/* Smooth Accordion Animation using Grid */}
                <div className={`grid transition-all duration-300 ease-in-out ${hasSubs && isExpanded ? 'grid-rows-[1fr] opacity-100' : 'grid-rows-[0fr] opacity-0'}`}>
                    <div className="overflow-hidden">
                        {hasSubs && <div className="mt-1 flex flex-col">{c.subClauses!.map(sub => renderClauseItem(sub, level + 1))}</div>}
                    </div>
                </div>
            </div>
        );
    };

    const renderClauses = () => {
        if (!standardKey || !standards[standardKey]) return <div className="text-center text-gray-400 mt-20 italic text-xs uppercase tracking-widest opacity-50">Select a Standard</div>;
        const data = standards[standardKey];

        const getGroupColorClass = (title: string) => {
            const t = title.toUpperCase();
            if (t.includes('PLAN')) return 'bg-blue-600 dark:bg-blue-500 shadow-blue-500/20';
            if (t.includes('SUPPORT')) return 'bg-purple-600 dark:bg-purple-500 shadow-purple-500/20';
            if (t.includes('DO')) return 'bg-orange-600 dark:bg-orange-500 shadow-orange-500/20';
            if (t.includes('CHECK') || t.includes('ACT')) return 'bg-emerald-600 dark:bg-emerald-500 shadow-emerald-500/20';
            if (t.includes('ANNEX')) return 'bg-rose-600 dark:bg-rose-500 shadow-rose-500/20';
            return 'bg-slate-800 dark:bg-slate-700';
        };

        return data.groups.map(g => {
            const isGroupExpanded = expandedGroups.includes(g.id) || !!searchQuery;
            const matchesSearch = (c: Clause): boolean => {
                const term = searchQuery.toLowerCase();
                return c.code.toLowerCase().includes(term) || c.title.toLowerCase().includes(term) || c.description.toLowerCase().includes(term) || (c.subClauses ? c.subClauses.some(matchesSearch) : false);
            };
            const filteredClauses = searchQuery ? g.clauses.filter(matchesSearch) : g.clauses;
            if (filteredClauses.length === 0) return null;

            return (
                <div key={g.id} className="mb-4 bg-white dark:bg-slate-900 rounded-2xl border border-gray-100 dark:border-slate-800 shadow-sm overflow-hidden transition-all duration-300 hover:shadow-md">
                    <div className="flex items-center justify-between p-3.5 bg-gray-50/50 dark:bg-slate-800/30 cursor-pointer hover:bg-gray-100 dark:hover:bg-slate-800 transition-colors" onClick={() => toggleGroupExpand(g.id)}>
                        <div className="flex items-center gap-3">
                            <button 
                                onClick={(e) => { e.stopPropagation(); toggleGroupSelection(g); }}
                                className={`p-2 rounded-xl shadow-lg text-white ${getGroupColorClass(g.title)} hover:scale-110 active:scale-95 transition-transform duration-300`}
                                title="Click to Select/Deselect All in Group"
                            >
                                <Icon name={g.icon} size={14}/>
                            </button>
                            <h4 className="text-xs font-black text-slate-950 dark:text-white uppercase tracking-widest">{g.title}</h4>
                        </div>
                        <Icon name="ChevronDown" size={12} className={`text-slate-400 transition-transform duration-300 ${isGroupExpanded ? 'rotate-180' : ''}`}/>
                    </div>
                    <div className={`grid transition-all duration-300 ease-in-out ${isGroupExpanded ? 'grid-rows-[1fr] opacity-100' : 'grid-rows-[0fr] opacity-0'}`}>
                        <div className="overflow-hidden bg-white dark:bg-slate-900">
                             <div className="p-2 space-y-1">{filteredClauses.map(c => renderClauseItem(c))}</div>
                        </div>
                    </div>
                </div>
            );
        });
    };

    const auditFieldIconColor = "text-indigo-700 dark:text-indigo-400";
    const health = runHealthCheck();
    const isCustomStandard = !STANDARDS_DATA[standardKey] || (standards[standardKey] && standards[standardKey] !== STANDARDS_DATA[standardKey]);

    const standardOptions = (() => {
        const rawOptions = Object.keys(standards).map(k => ({ value: k, label: standards[k].name }));
        const seen = new Set();
        const unique = rawOptions.filter(item => {
            const duplicate = seen.has(item.label);
            seen.add(item.label);
            return !duplicate;
        });
        return [...unique, {value: "ADD_NEW", label: "+ Add New Standard..."}];
    })();

    return (
        <div 
            ref={sidebarRef}
            className={`${isOpen ? 'border-r' : 'w-0 border-0 overflow-hidden'} flex flex-col bg-white dark:bg-slate-900 border-gray-200 dark:border-slate-800 shadow-2xl z-50 relative shrink-0 ${isResizing ? 'transition-none' : 'transition-[width] duration-500 ease-fluid-spring'} h-full`} 
            style={{ width: isOpen ? (window.innerWidth < 768 ? '100%' : width) : 0 }}
        >
             {isOpen && <div className="absolute right-0 top-0 bottom-0 w-1.5 cursor-col-resize hover:bg-indigo-500 transition-colors z-50 group resize-handle hidden md:block" onMouseDown={startResizing} />}

            <div className={`flex-shrink-0 bg-white dark:bg-slate-900 w-full md:min-w-[390px] flex flex-col gap-3 transition-all duration-700 ease-fluid-spring overflow-hidden will-change-auto ${isHeaderVisible ? 'max-h-[1000px] opacity-100 p-5 border-b border-gray-100 dark:border-slate-800' : 'max-h-0 opacity-0 p-0 border-none'}`}>

                {/* Standard Selector - Clean & Prominent */}
                <div className="relative">
                    <IconSelect 
                        icon="Book" 
                        iconColor={auditFieldIconColor} 
                        value={standardKey} 
                        onChange={(e: any) => { if (e.target.value === "ADD_NEW") onAddNewStandard(); else setStandardKey(e.target.value); }} 
                        options={standardOptions} 
                        defaultText="Select ISO Standard" 
                    />
                    {standardKey && (
                        <button onClick={() => setShowIntegrityModal(true)} className={`absolute -top-2 -right-2 p-1.5 rounded-full shadow-2xl transition-all duration-300 hover:scale-110 active:scale-95 text-white ring-4 ring-white dark:ring-slate-900 ${health.isHealthy ? 'bg-emerald-500' : 'bg-orange-500'}`} title="Standard Integrity Status">
                            <Icon name={health.isHealthy ? "CheckCircle2" : "AlertCircle"} size={14}/>
                        </button>
                    )}
                </div>

                {/* Audit Context - Collapsible Accordion to save visual space */}
                <div className={`border rounded-xl overflow-hidden transition-all duration-300 ${
                    !isInfoExpanded 
                    ? 'border-gray-100 dark:border-slate-800 bg-white dark:bg-slate-900' 
                    : 'border-indigo-100 dark:border-slate-700 shadow-sm'
                }`}>
                    <button 
                        onClick={() => setIsInfoExpanded(!isInfoExpanded)}
                        className="w-full flex items-center justify-between p-3 transition-colors duration-300 hover:bg-gray-50 dark:hover:bg-slate-800/50"
                    >
                        <span className="text-[10px] font-bold text-slate-500 uppercase tracking-widest flex items-center gap-2">
                             <div className={`transition-all duration-300 ${isInfoExpanded ? 'text-indigo-500' : 'text-slate-400'}`}>
                                <Icon name="Info" size={14} />
                            </div>
                            Context & Details
                        </span>
                        <Icon name="ChevronDown" size={12} className={`text-slate-400 transition-transform duration-300 ${isInfoExpanded ? 'rotate-180' : ''}`}/>
                    </button>

                    <div className={`grid transition-all duration-300 ease-in-out ${isInfoExpanded ? 'grid-rows-[1fr] opacity-100' : 'grid-rows-[0fr] opacity-0'}`}>
                        <div className="overflow-hidden">
                             <div className="p-3 bg-gray-50/50 dark:bg-slate-900/50 space-y-3 border-t border-gray-100 dark:border-slate-800">
                                <IconSelect icon="FileEdit" iconColor={auditFieldIconColor} value={auditInfo.type} onChange={(e: any) => setAuditInfo({...auditInfo, type: e.target.value})} options={Object.keys(AUDIT_TYPES).map(key => ({ value: key, label: key }))} defaultText="Select Audit Type" />
                                <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                                    <IconInput icon="Building" iconColor={auditFieldIconColor} placeholder="Company Name" value={auditInfo.company} onChange={(e: any) => setAuditInfo({...auditInfo, company: e.target.value})} />
                                    <IconInput icon="Tag" iconColor={auditFieldIconColor} placeholder="# SMO" value={auditInfo.smo} onChange={(e: any) => setAuditInfo({...auditInfo, smo: e.target.value})} />
                                </div>
                                <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                                    <IconInput icon="Users" iconColor={auditFieldIconColor} placeholder="Department" value={auditInfo.department} onChange={(e: any) => setAuditInfo({...auditInfo, department: e.target.value})} />
                                    <IconInput icon="User" iconColor={auditFieldIconColor} placeholder="Auditee/Auditor" value={auditInfo.interviewee} onChange={(e: any) => setAuditInfo({...auditInfo, interviewee: e.target.value})} />
                                    <IconInput icon="AuditUser" iconColor={auditFieldIconColor} placeholder="Lead Auditor Name" value={auditInfo.auditor} onChange={(e: any) => setAuditInfo({...auditInfo, auditor: e.target.value})} />
                                </div>
                            </div>
                        </div>
                    </div>
                </div>
            </div>

            <div className="flex-1 flex flex-col min-h-0 bg-gray-50/40 dark:bg-slate-950/40 w-full md:min-w-[390px]">
                <div className={`p-3 border-b border-gray-100 dark:border-slate-800 bg-white dark:bg-slate-900 shadow-sm z-10 sticky top-0 transition-all duration-500 ${!isHeaderVisible ? 'shadow-md border-indigo-100 dark:border-indigo-900/50' : ''}`}>
                    <div className="flex items-center gap-2">
                        <div className="relative flex-1 flex items-center gap-1 bg-gray-100 dark:bg-slate-800 rounded-xl px-2 transition-all focus-within:ring-2 focus-within:ring-indigo-500/20">
                            <span className="text-blue-700 dark:text-blue-400 font-bold pl-1"><Icon name="Search" size={14}/></span>
                            <input className="w-full bg-transparent py-2 px-1 text-xs font-medium outline-none text-slate-800 dark:text-slate-200 placeholder-gray-400" placeholder="Search content..." value={searchQueryRaw} onChange={e => setSearchQueryRaw(e.target.value)}/>

                            <button 
                                onClick={toggleExpandAll} 
                                className="p-1.5 rounded-lg hover:bg-white dark:hover:bg-slate-700 text-slate-400 hover:text-indigo-600 dark:hover:text-indigo-400 transition-colors"
                                title={areAllGroupsExpanded ? "Collapse All Groups" : "Expand All Groups"}
                            >
                                <Icon name={areAllGroupsExpanded ? "CollapsePanel" : "ExpandPanel"} size={14}/>
                            </button>
                        </div>

                        {selectedClauses.length > 0 && (
                            <div className="flex gap-2 animate-in fade-in slide-in-from-right-5 duration-300">
                                <button onClick={handleCopySelectedClauses} className="p-2 rounded-xl bg-indigo-50 dark:bg-indigo-900/20 text-indigo-600 hover:bg-indigo-100 transition-colors relative shadow-sm border border-indigo-100 dark:border-indigo-900/30 hover:scale-105" title="Copy Selected Clauses">
                                    <Icon name="Copy" size={16} />
                                </button>
                                <button onClick={() => setSelectedClauses([])} className="p-2 rounded-xl bg-red-50 dark:bg-red-900/20 text-red-600 hover:bg-red-100 transition-colors relative shadow-sm border border-red-100 dark:border-red-900/30 hover:scale-105" title="Clear All">
                                    <Icon name="Trash2" size={16} />
                                    <div className="absolute -top-1 -right-1 bg-red-600 text-white text-[9px] font-black w-4 h-4 rounded-full flex items-center justify-center border-2 border-white dark:border-slate-900 shadow-sm animate-bounce">{selectedClauses.length}</div>
                                </button>
                            </div>
                        )}
                    </div>
                </div>
                {/* 
                   MAJOR FIX: "min-h-[150vh]" forces a scroll runway.
                   This ensures there is ALWAYS enough content to scroll down and hide the header,
                   even if the actual list of clauses is very short.
                   The whitespace at the bottom acts as a buffer.
                */}
                <div 
                    ref={scrollContainerRef}
                    className="flex-1 overflow-y-auto custom-scrollbar p-3 scroll-smooth"
                    onScroll={handleScroll}
                >
                    <div className="min-h-[150vh] flex flex-col">
                        {renderClauses()}
                        <div className="flex-1"></div> {/* Spacer to fill remaining height */}
                    </div>
                </div>
            </div>

            <Modal isOpen={showIntegrityModal} title="Standard Health Index" onClose={() => setShowIntegrityModal(false)}>
                {/* Modal content preserved... */}
                 <div className="space-y-6">
                    {/* ... (Existing modal content) ... */}
                    <div className="flex items-center gap-5 p-5 rounded-3xl bg-gray-50 dark:bg-slate-800 border border-gray-100 dark:border-slate-700 shadow-inner">
                        <div className={`w-20 h-20 rounded-full flex items-center justify-center text-white text-2xl font-black shadow-xl ring-4 ring-white dark:ring-slate-700 ${health.score > 90 ? 'bg-gradient-to-br from-emerald-400 to-emerald-600' : 'bg-gradient-to-br from-orange-400 to-orange-600'}`}>
                            {health.score}%
                        </div>
                        <div className="flex-1">
                            <h4 className="font-black text-slate-900 dark:text-slate-100 uppercase tracking-tight">Data Health</h4>
                            <p className="text-xs text-slate-500 dark:text-slate-400 leading-snug mt-1">{health.isHealthy ? 'Excellent! Data is accurate, clean, and complete for professional use.' : 'Standard data is incomplete or contains errors. Please review.'}</p>
                        </div>
                    </div>
                    {/* ... (Rest of integrity modal) ... */}
                     <div className="mt-6 pt-4 border-t border-gray-100 dark:border-slate-700 flex justify-end gap-3">
                     {isCustomStandard && (
                        <button 
                            onClick={() => {
                                if(confirm("Are you sure? This will remove all AI repairs and revert to the original static data.")) {
                                    onResetStandard(standardKey);
                                    setShowIntegrityModal(false);
                                    setRepairStats(null);
                                    setRepairedIds([]);
                                }
                            }} 
                            className="px-4 py-2 bg-red-50 hover:bg-red-100 text-red-600 dark:bg-red-900/20 dark:hover:bg-red-900/40 dark:text-red-400 rounded-xl font-bold text-xs flex items-center gap-2 transition-all active:scale-95 border border-red-200 dark:border-red-800"
                        >
                            <Icon name="Trash2" size={14}/>
                            Reset to Default
                        </button>
                     )}

                     {repairStats ? (
                         <div className="flex items-center gap-3 animate-in fade-in slide-in-from-right-5">
                            <div className="text-right">
                                <p className="text-[10px] font-bold text-emerald-600 uppercase">Repair Complete</p>
                                <p className="text-xs text-slate-500">Added {repairStats.fixed} items, Cleaned {repairStats.cleaned} dupes.</p>
                            </div>
                            <button onClick={() => setShowIntegrityModal(false)} className="px-4 py-2 bg-emerald-500 hover:bg-emerald-600 text-white rounded-xl font-bold text-xs shadow-lg shadow-emerald-500/30">
                                Close & Continue
                            </button>
                         </div>
                     ) : !health.isHealthy && (
                         <button 
                            onClick={handleAutoRepair} 
                            disabled={isRepairing}
                            className="px-4 py-2 bg-indigo-600 hover:bg-indigo-700 text-white rounded-xl font-bold text-xs flex items-center gap-2 shadow-lg shadow-indigo-500/30 transition-all active:scale-95 disabled:opacity-70 disabled:active:scale-100"
                        >
                            {isRepairing ? <Icon name="Loader" className="animate-spin"/> : <Icon name="Wand2"/>}
                            {isRepairing ? "AI is Fixing..." : "Auto-Repair Issues with AI"}
                        </button>
                     )}
                 </div>
                 </div>
            </Modal>
        </div>
    );
};
export default Sidebar;

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { APP_VERSION, STANDARDS_DATA, INITIAL_EVIDENCE } from './constants';
import { StandardsData, AuditInfo, AnalysisResult, Standard, ApiKeyProfile, Clause, FindingsViewMode } from './types';
import { Icon, FontSizeController, SparkleLoader, Modal, IconInput, AINeuralLoader, Toast, CommandPaletteModal } from './components/UI';
import Sidebar from './components/Sidebar';
import ReleaseNotesModal from './components/ReleaseNotesModal';
import { generateOcrContent, generateAnalysis, generateTextReport, validateApiKey } from './services/geminiService';
import { cleanAndParseJSON, fileToBase64, cleanFileName } from './utils';

declare var mammoth: any;

type LayoutMode = 'evidence' | 'findings' | 'report' | 'split';
type ExportLanguage = 'en' | 'vi';

// Strictly Infinity Only
type LogoEffect = 'infinity';

function App() {
    // -- STATE --
    const [fontSizeScale, setFontSizeScale] = useState(1.0);
    const [isDarkMode, setIsDarkMode] = useState(true);
    const [sidebarWidth, setSidebarWidth] = useState(390);
    const [isSidebarOpen, setIsSidebarOpen] = useState(true);
    const [showAboutModal, setShowAboutModal] = useState(false);
    const [showSettingsModal, setShowSettingsModal] = useState(false);

    // Feature: Command Palette
    const [isCmdPaletteOpen, setIsCmdPaletteOpen] = useState(false);

    // Feature: Matrix View
    const [findingsViewMode, setFindingsViewMode] = useState<FindingsViewMode>('list');

    // New: Track Window Width for responsive calculations in JS
    const [windowWidth, setWindowWidth] = useState(window.innerWidth);

    // API Key Management State
    const [apiKeys, setApiKeys] = useState<ApiKeyProfile[]>([]);
    const [activeKeyId, setActiveKeyId] = useState<string>("");
    const [newKeyInput, setNewKeyInput] = useState("");
    const [newKeyLabel, setNewKeyLabel] = useState("");
    const [isCheckingKey, setIsCheckingKey] = useState(false);

    // Toast State
    const [toastMsg, setToastMsg] = useState<string | null>(null);

    const [exportLanguage, setExportLanguage] = useState<ExportLanguage>('en');
    const [notesLanguage, setNotesLanguage] = useState<ExportLanguage>('vi'); 
    const [evidenceLanguage, setEvidenceLanguage] = useState<ExportLanguage>('en'); // New state for Evidence export
    const [isDragging, setIsDragging] = useState(false);

    const [reportTemplate, setReportTemplate] = useState<string>("");
    const [templateFileName, setTemplateFileName] = useState<string>("");

    const [customStandards, setCustomStandards] = useState<StandardsData>({});
    const [standardKey, setStandardKey] = useState<string>("ISO 9001:2015");
    const [auditInfo, setAuditInfo] = useState<AuditInfo>({ company: "", smo: "", department: "", interviewee: "", auditor: "", type: "" });
    const [selectedClauses, setSelectedClauses] = useState<string[]>([]);
    const [evidence, setEvidence] = useState(INITIAL_EVIDENCE);
    const [pastedImages, setPastedImages] = useState<File[]>([]);

    const [analysisResult, setAnalysisResult] = useState<AnalysisResult[] | null>(null);
    const [selectedFindings, setSelectedFindings] = useState<Record<string, boolean>>({});
    const [finalReportText, setFinalReportText] = useState<string | null>(null);
    const [layoutMode, setLayoutMode] = useState('evidence' as LayoutMode);

    // Loading States
    const [isOcrLoading, setIsOcrLoading] = useState(false);
    const [isAnalyzeLoading, setIsAnalyzeLoading] = useState(false);
    const [currentAnalyzingClause, setCurrentAnalyzingClause] = useState<string>(""); // Track specifically which clause is processing
    const [loadingMessage, setLoadingMessage] = useState<string>(""); 
    const [isReportLoading, setIsReportLoading] = useState(false);
    const [isExportLoading, setIsExportLoading] = useState(false);
    const [isNotesExportLoading, setIsNotesExportLoading] = useState(false);
    const [isEvidenceExportLoading, setIsEvidenceExportLoading] = useState(false); 

    const [aiError, setAiError] = useState<string | null>(null);

    // Logo Animation State - Fixed to Infinity
    const [logoKey, setLogoKey] = useState(0);
    const logoEffect: LogoEffect = 'infinity';

    // Fluid Tab State
    const [tabStyle, setTabStyle] = useState({ left: 0, width: 0, opacity: 0 });
    const tabsRef = useRef<(HTMLButtonElement | null)[]>([]);
    const tabsContainerRef = useRef<HTMLDivElement>(null); 

    const tabsList = [
        { id: 'evidence', label: 'Evidence', icon: 'ScanText' }, 
        { id: 'findings', label: 'Findings', icon: 'Wand2' }, 
        { id: 'report', label: 'Report', icon: 'FileText' }
    ];

    const fileInputRef = useRef<HTMLInputElement>(null);
    const templateInputRef = useRef<HTMLInputElement>(null);
    const evidenceTextareaRef = useRef<HTMLTextAreaElement>(null);
    const hasStartupChecked = useRef(false);
    const findingsContainerRef = useRef<HTMLDivElement>(null);

    const allStandards = { ...STANDARDS_DATA, ...customStandards };
    const hasEvidence = evidence.trim().length > 0 || pastedImages.length > 0;

    // NEW: Strict Readiness Check
    const isReadyForAnalysis = !isAnalyzeLoading && selectedClauses.length > 0 && hasEvidence;

    // --- HELPER: INSERT TEXT AT CURSOR ---
    const insertTextAtCursor = (textToInsert: string) => {
        if (evidenceTextareaRef.current) {
            const textarea = evidenceTextareaRef.current;
            const start = textarea.selectionStart;
            const end = textarea.selectionEnd;
            const newValue = evidence.substring(0, start) + textToInsert + evidence.substring(end);

            setEvidence(newValue);

            // Set layout to evidence if not already
            if (layoutMode !== 'evidence') setLayoutMode('evidence');

            // Defer focus to allow state update and layout switch
            setTimeout(() => {
                if (evidenceTextareaRef.current) {
                    evidenceTextareaRef.current.focus();
                    evidenceTextareaRef.current.setSelectionRange(start + textToInsert.length, start + textToInsert.length);
                }
            }, 100);
        } else {
            // Fallback if textarea ref is not active (e.g., viewing report tab), just append
            setEvidence(prev => prev + "\n" + textToInsert);
            if (layoutMode !== 'evidence') setLayoutMode('evidence');
        }
    };

    // --- EFFECTS & PERSISTENCE ---
    useEffect(() => {
        // Init load
        const storedScale = localStorage.getItem('iso_font_scale');
        if (storedScale) setFontSizeScale(parseFloat(storedScale));

        loadSessionData(); // Load all saved data

        // Initial Key Load
        const loadedKeys = loadKeyData(); // Now returns keys for immediate use

        // Auto Precheck API Key on Startup
        if (!hasStartupChecked.current && loadedKeys.length > 0) {
            hasStartupChecked.current = true;
            checkAllKeys(loadedKeys);
        }

        const savedDarkMode = localStorage.getItem('iso_dark_mode');
        if (savedDarkMode !== null) {
            setIsDarkMode(savedDarkMode === 'true');
        } else {
            setIsDarkMode(true); 
        }

        // Mobile: Auto close sidebar on initial load if screen is small
        if (window.innerWidth < 768) {
            setIsSidebarOpen(false);
        }

        // Window resize listener to track full width
        const handleResize = () => setWindowWidth(window.innerWidth);
        window.addEventListener('resize', handleResize);
        return () => window.removeEventListener('resize', handleResize);
    }, []);

    // Update Fluid Tab Position - Enhanced Logic
    useEffect(() => {
        const updateTabs = () => {
            const activeIndex = tabsList.findIndex(t => t.id === layoutMode);
            const el = tabsRef.current[activeIndex];
            if (el) {
                setTabStyle({
                    left: el.offsetLeft,
                    width: el.offsetWidth,
                    opacity: 1
                });
            }
        };

        // 1. Run immediately
        updateTabs();

        // 2. Run slightly delayed to catch font reflows
        const t = setTimeout(updateTabs, 50);

        // 3. ResizeObserver for robust layout tracking
        const observer = new ResizeObserver(() => {
            updateTabs();
        });

        if (tabsContainerRef.current) {
            observer.observe(tabsContainerRef.current);
        }

        return () => {
            clearTimeout(t);
            observer.disconnect();
        };
    }, [layoutMode, sidebarWidth, fontSizeScale]); 

    // Auto-scroll findings
    useEffect(() => {
        if (layoutMode === 'findings' && findingsContainerRef.current) {
            findingsContainerRef.current.scrollTop = findingsContainerRef.current.scrollHeight;
        }
    }, [analysisResult]);

    const loadSessionData = () => {
        try {
            const savedAuditInfo = localStorage.getItem("iso_audit_info");
            const savedEvidence = localStorage.getItem("iso_evidence");
            const savedStandardKey = localStorage.getItem("iso_standard_key");
            const savedSelectedClauses = localStorage.getItem("iso_selected_clauses");
            const savedTemplate = localStorage.getItem('iso_report_template');
            const savedTemplateName = localStorage.getItem('iso_report_template_name');

            if (savedAuditInfo) setAuditInfo(JSON.parse(savedAuditInfo));
            if (savedEvidence && savedEvidence.trim() !== '') setEvidence(savedEvidence);
            if (savedStandardKey) setStandardKey(savedStandardKey);
            if (savedSelectedClauses) setSelectedClauses(JSON.parse(savedSelectedClauses));
            if (savedTemplate) setReportTemplate(savedTemplate);
            if (savedTemplateName) setTemplateFileName(savedTemplateName);
        } catch (e) {
            console.error("Failed to load session data", e);
        }
    };

    const loadKeyData = (): ApiKeyProfile[] => {
        try {
            const savedKeys = localStorage.getItem("iso_api_keys");
            const savedActiveId = localStorage.getItem("iso_active_key_id");
            // Migration for legacy single key
            const legacyKey = localStorage.getItem("iso_api_key");

            let loadedKeys: ApiKeyProfile[] = [];

            if (savedKeys) {
                loadedKeys = JSON.parse(savedKeys);
            } else if (legacyKey) {
                // Migrate legacy key to new structure
                const newId = Date.now().toString();
                loadedKeys = [{
                    id: newId,
                    label: "Default Key",
                    key: legacyKey,
                    status: 'unknown',
                    latency: 0,
                    lastChecked: new Date().toISOString()
                }];
                setActiveKeyId(newId);
                localStorage.setItem("iso_active_key_id", newId);
            }

            setApiKeys(loadedKeys);
            if (savedActiveId) {
                setActiveKeyId(savedActiveId);
            } else if (loadedKeys.length > 0) {
                setActiveKeyId(loadedKeys[0].id);
            }
            return loadedKeys;
        } catch (e) { 
            console.error("Failed to load keys", e); 
            return [];
        }
    };

    // Real-time Saving
    useEffect(() => {
        if (isDarkMode) document.body.classList.add('dark');
        else {
            document.body.classList.remove('dark');
        }
        localStorage.setItem('iso_dark_mode', String(isDarkMode));
    }, [isDarkMode]);

    useEffect(() => {
        document.documentElement.style.setProperty('--font-scale', fontSizeScale.toString());
        localStorage.setItem('iso_font_scale', fontSizeScale.toString());
    }, [fontSizeScale]);

    useEffect(() => { localStorage.setItem("iso_audit_info", JSON.stringify(auditInfo)); }, [auditInfo]);
    useEffect(() => { localStorage.setItem("iso_evidence", evidence); }, [evidence]);
    useEffect(() => { localStorage.setItem("iso_standard_key", standardKey); }, [standardKey]);
    useEffect(() => { localStorage.setItem("iso_selected_clauses", JSON.stringify(selectedClauses)); }, [selectedClauses]);

    useEffect(() => {
        localStorage.setItem('iso_report_template', reportTemplate);
        localStorage.setItem('iso_report_template_name', templateFileName);
    }, [reportTemplate, templateFileName]);

    // Save Keys and update the 'legacy' key slot for geminiService usage
    useEffect(() => {
        localStorage.setItem("iso_api_keys", JSON.stringify(apiKeys));
        localStorage.setItem("iso_active_key_id", activeKeyId);

        const activeProfile = apiKeys.find(k => k.id === activeKeyId);
        if (activeProfile) {
            localStorage.setItem("iso_api_key", activeProfile.key);
        } else {
            localStorage.removeItem("iso_api_key");
        }
    }, [apiKeys, activeKeyId]);

    // --- API KEY HANDLERS ---

    const checkAllKeys = async (initialKeys: ApiKeyProfile[]) => {
        // Set all to checking state visually
        setApiKeys(prev => prev.map(k => ({ ...k, status: 'checking' })));

        const checkedKeys = await Promise.all(initialKeys.map(async (profile) => {
            const result = await validateApiKey(profile.key);
            return {
                ...profile,
                status: result.isValid ? 'valid' : (result.errorType || 'invalid'),
                latency: result.latency,
                lastChecked: new Date().toISOString()
            } as ApiKeyProfile;
        }));

        setApiKeys(checkedKeys);

        // Auto-switch logic: 
        // 1. Is the current active key valid?
        const currentActive = checkedKeys.find(k => k.id === localStorage.getItem("iso_active_key_id"));

        if (!currentActive || currentActive.status !== 'valid') {
            // Find the best valid key (lowest latency)
            const bestKey = checkedKeys
                .filter(k => k.status === 'valid')
                .sort((a, b) => a.latency - b.latency)[0];

            if (bestKey) {
                setActiveKeyId(bestKey.id);
                setToastMsg(`Switched to active key: ${bestKey.label}`);
            }
        }
    };

    const checkKeyStatus = async (id: string, keyStr: string) => {
        setApiKeys(prev => prev.map(k => k.id === id ? { ...k, status: 'checking' } : k));
        const result = await validateApiKey(keyStr);
        setApiKeys(prev => prev.map(k => k.id === id ? { 
            ...k, 
            status: result.isValid ? 'valid' : (result.errorType || 'invalid'),
            latency: result.latency,
            lastChecked: new Date().toISOString()
        } : k));
        return result.isValid;
    };

    const handleAddKey = async () => {
        if (!newKeyInput.trim()) return;
        setIsCheckingKey(true);
        const tempId = Date.now().toString();

        // Validate before adding
        const validation = await validateApiKey(newKeyInput);

        const newProfile: ApiKeyProfile = {
            id: tempId,
            label: newKeyLabel || `API Key ${apiKeys.length + 1}`,
            key: newKeyInput,
            status: validation.isValid ? 'valid' : (validation.errorType || 'invalid'),
            latency: validation.latency,
            lastChecked: new Date().toISOString()
        };

        setApiKeys(prev => [...prev, newProfile]);
        // If it's the first key, make it active
        if (apiKeys.length === 0) setActiveKeyId(tempId);

        setNewKeyInput("");
        setNewKeyLabel("");
        setIsCheckingKey(false);
    };

    const handleDeleteKey = (id: string) => {
        const remaining = apiKeys.filter(k => k.id !== id);
        setApiKeys(remaining);
        if (activeKeyId === id && remaining.length > 0) {
            setActiveKeyId(remaining[0].id);
        } else if (remaining.length === 0) {
            setActiveKeyId("");
        }
    };

    const handleRefreshStatus = async (id: string) => {
        const keyProfile = apiKeys.find(k => k.id === id);
        if (keyProfile) {
            await checkKeyStatus(id, keyProfile.key);
        }
    };

    // --- RECURSIVE EXECUTION WITH SMART FAILOVER ---

    const executeWithApiKeyFailover = async <T,>(
        operation: (apiKey: string) => Promise<T>, 
        attemptedKeys: string[] = []
    ): Promise<T> => {
        // 1. Get current pool of usable keys (excluding ones we already failed on this specific call)
        const availableKeys = apiKeys.filter(k => 
            k.status !== 'invalid' && // Don't use known bad keys
            k.status !== 'quota_exceeded' && // Don't use exhausted keys
            !attemptedKeys.includes(k.id) // Don't reuse keys we tried in this recursive chain
        );

        // Sort by latency (lowest first) to prioritize fast keys
        availableKeys.sort((a, b) => a.latency - b.latency);

        // 2. Identify candidate key
        // Prefer the currently active key if it's in the available list, otherwise take the best one
        let candidateKey = availableKeys.find(k => k.id === activeKeyId);
        if (!candidateKey && availableKeys.length > 0) {
            candidateKey = availableKeys[0];
        }

        if (!candidateKey) {
            // No keys left to try
            throw new Error("ALL_KEYS_EXHAUSTED");
        }

        // Switch active key state if we had to failover to a new one
        if (candidateKey.id !== activeKeyId) {
            setActiveKeyId(candidateKey.id);
            setToastMsg(`Switching to backup key: ${candidateKey.label}...`);
        }

        try {
            // 3. Attempt Execution
            return await operation(candidateKey.key);
        } catch (error: any) {
            console.warn(`Key [${candidateKey.label}] failed. Error:`, error);

            const msg = error.message?.toLowerCase() || "";
            const isApiError = msg.includes("403") || msg.includes("429") || msg.includes("quota") || msg.includes("key") || msg.includes("permission") || msg.includes("resource exhausted");

            if (isApiError) {
                // 4. Mark failure in global state so other clauses don't waste time on this key
                setApiKeys(prev => prev.map(k => k.id === candidateKey!.id ? { ...k, status: 'quota_exceeded' } : k));

                // 5. Recursive Retry with the next key
                return await executeWithApiKeyFailover(operation, [...attemptedKeys, candidateKey.id]);
            }
            // Non-API error (e.g. parsing, network disconnect) - rethrow
            throw error;
        }
    };

    // --- MAIN HANDLERS ---

    const handleNewSession = () => {
        if (window.confirm("Start new session? Current work will be cleared.")) {
            setAuditInfo({ company: "", smo: "", department: "", interviewee: "", auditor: "", type: "" });
            setSelectedClauses([]);
            setEvidence(INITIAL_EVIDENCE);
            setPastedImages([]);
            setAnalysisResult(null);
            setSelectedFindings({});
            setFinalReportText(null);
            setLayoutMode('evidence');
            setAiError(null);
        }
    };

    const handleRecall = () => {
        loadSessionData();
        const notification = document.createElement("div");
        notification.textContent = "Session Recalled Successfully";
        notification.className = "fixed bottom-5 right-5 bg-emerald-500 text-white px-4 py-2 rounded-xl shadow-xl z-[9999] animate-in slide-in-from-bottom-5";
        document.body.appendChild(notification);
        setTimeout(() => notification.remove(), 2000);
    };

    const handleUpdateStandard = (updated: Standard) => {
        setCustomStandards(prev => ({ ...prev, [updated.name]: updated }));
    };

    const handleResetStandard = (key: string) => {
        setCustomStandards(prev => {
