                                                    {result.suggestion && <div className="mt-2 flex gap-2 items-start"><Icon name="Lightbulb" size={14} className="text-amber-500 mt-0.5"/><p className="text-xs text-slate-600 dark:text-slate-300">{result.suggestion}</p></div>}
