                                            <h4 className="text-lg font-bold text-slate-700 dark:text-slate-200 mb-2">Ready to Synthesize</h4>
                                            <p className="text-sm text-slate-500 max-w-md mb-6">Generate a comprehensive audit report based on {Object.keys(selectedFindings).length} identified findings and context data.</p>

                                            <button onClick={handleGenerateReport} disabled={!analysisResult || analysisResult.length === 0} className="px-8 py-3 bg-gradient-to-r from-indigo-600 to-purple-600 text-white rounded-xl font-bold text-sm shadow-xl shadow-indigo-500/30 hover:scale-105 transition-transform flex items-center gap-3 disabled:opacity-50 disabled:cursor-not-allowed">
                                                {isReportLoading ? <SparkleLoader className="text-white"/> : <Icon name="Wand2" size={18}/>}
                                                {isReportLoading ? "Synthesizing Report..." : "Generate Final Report"}
                                            </button>
                                        </div>
                                    ) : (
                                        <textarea 
                                            className="flex-1 w-full h-full bg-transparent resize-none focus:outline-none text-slate-800 dark:text-slate-200 font-mono text-sm leading-relaxed" 
                                            value={finalReportText} 
                                            onChange={(e) => setFinalReportText(e.target.value)}
                                        />
                                    )}
                                </div>
                            </div>
                        )}
                    </div>
                </div>
            </div>

            {/* MODALS */}
            <CommandPaletteModal 
                isOpen={isCmdPaletteOpen} 
                onClose={() => setIsCmdPaletteOpen(false)}
                actions={commandActions}
                onSelectAction={(item: any) => {
                    item.action();
                    setIsCmdPaletteOpen(false);
                }}
            />

            <ReleaseNotesModal isOpen={showAboutModal} onClose={() => setShowAboutModal(false)} />

            {/* Settings Modal - API Keys */}
            <Modal isOpen={showSettingsModal} title="Settings & API Keys" onClose={() => setShowSettingsModal(false)}>
                <div className="space-y-6">
                    <div>
                        <h4 className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-3">Manage API Keys</h4>
                        <div className="space-y-3">
                            {/* Key List */}
                            {apiKeys.map(profile => (
                                <div key={profile.id} className={`p-3 rounded-xl border flex items-center justify-between transition-all ${profile.id === activeKeyId ? 'bg-indigo-50 border-indigo-200 dark:bg-indigo-900/20 dark:border-indigo-800' : 'bg-white border-gray-100 dark:bg-slate-800 dark:border-slate-700'}`}>
                                    <div className="flex items-center gap-3 overflow-hidden">
                                        <div onClick={() => setActiveKeyId(profile.id)} className={`cursor-pointer w-4 h-4 rounded-full border-2 flex items-center justify-center ${profile.id === activeKeyId ? 'border-indigo-500' : 'border-gray-300 dark:border-slate-500'}`}>
                                            {profile.id === activeKeyId && <div className="w-2 h-2 rounded-full bg-indigo-500"></div>}
                                        </div>
                                        <div className="flex flex-col min-w-0">
                                            <div className="flex items-center gap-2">
                                                <span className="text-sm font-bold text-slate-700 dark:text-slate-200 truncate">{profile.label}</span>
                                                {profile.status === 'valid' && <span className="text-[9px] bg-emerald-100 text-emerald-700 px-1.5 py-0.5 rounded font-bold uppercase">Valid</span>}
                                                {profile.status === 'invalid' && <span className="text-[9px] bg-red-100 text-red-700 px-1.5 py-0.5 rounded font-bold uppercase">Invalid</span>}
                                                {profile.status === 'quota_exceeded' && <span className="text-[9px] bg-orange-100 text-orange-700 px-1.5 py-0.5 rounded font-bold uppercase">Quota</span>}
                                                {profile.status === 'checking' && <Icon name="Loader" size={10} className="animate-spin text-indigo-500"/>}
                                            </div>
                                            <span className="text-[10px] text-slate-400 font-mono truncate">
                                                {profile.key.substring(0, 8)}...{profile.key.substring(profile.key.length - 4)} • {profile.latency > 0 ? `${profile.latency}ms` : 'Unknown'}
                                            </span>
                                        </div>
                                    </div>
                                    <div className="flex items-center gap-1">
                                         <button onClick={() => handleRefreshStatus(profile.id)} className="p-2 text-slate-400 hover:text-indigo-500 hover:bg-indigo-50 dark:hover:bg-slate-700 rounded-lg transition-colors" title="Check Status">
                                            <Icon name="RefreshCw" size={14} className={profile.status === 'checking' ? 'animate-spin' : ''}/>
                                        </button>
                                        <button onClick={() => handleDeleteKey(profile.id)} className="p-2 text-slate-400 hover:text-red-500 hover:bg-red-50 dark:hover:bg-red-900/20 rounded-lg transition-colors" title="Remove Key">
                                            <Icon name="Trash2" size={14}/>
                                        </button>
                                    </div>
                                </div>
                            ))}

                            {/* Add New Key Input */}
                            <div className="p-3 bg-gray-50 dark:bg-slate-800/50 rounded-xl border border-dashed border-gray-300 dark:border-slate-700 flex flex-col gap-3">
                                <input 
                                    className="w-full bg-transparent text-xs outline-none text-slate-700 dark:text-slate-300 placeholder-gray-400 border-b border-gray-200 dark:border-slate-700 pb-2 focus:border-indigo-500 transition-colors"
                                    placeholder="Enter Google Gemini API Key (starts with AIza...)"
                                    value={newKeyInput}
                                    onChange={(e) => setNewKeyInput(e.target.value)}
                                />
                                <div className="flex gap-2">
                                    <input 
                                        className="flex-1 bg-transparent text-xs outline-none text-slate-700 dark:text-slate-300 placeholder-gray-400 border-b border-gray-200 dark:border-slate-700 pb-2 focus:border-indigo-500 transition-colors"
                                        placeholder="Label (Optional, e.g. 'Personal Key')"
                                        value={newKeyLabel}
                                        onChange={(e) => setNewKeyLabel(e.target.value)}
                                    />
                                    <button 
                                        onClick={handleAddKey} 
                                        disabled={!newKeyInput || isCheckingKey}
                                        className="px-4 py-1.5 bg-indigo-600 hover:bg-indigo-700 disabled:opacity-50 disabled:cursor-not-allowed text-white text-xs font-bold rounded-lg transition-all shadow-sm"
                                    >
                                        {isCheckingKey ? <Icon name="Loader" className="animate-spin"/> : "Add Key"}
                                    </button>
                                </div>
                            </div>
                        </div>
                    </div>

                    <div className="bg-indigo-50 dark:bg-indigo-900/20 p-4 rounded-xl flex gap-3">
                        <Icon name="Info" className="text-indigo-600 dark:text-indigo-400 shrink-0 mt-0.5" size={16}/>
                        <p className="text-xs text-indigo-800 dark:text-indigo-300 leading-relaxed">
                            <strong>Note:</strong> Multiple keys are supported for "Failover Strategy". If one key hits the rate limit (Quota Exceeded), the system automatically switches to the next available valid key to continue your audit without interruption.
                        </p>
                    </div>
                </div>
            </Modal>

            {/* Global Loading Overlay (if needed for heavy non-streaming tasks) */}
            {/* Using inline loading mostly, but if we need a blocker: */}
            {isReportLoading && <AINeuralLoader message="Synthesizing Audit Report..." />}
        </div>
    );
}

export default App;

import React, { useState, useCallback } from 'react';
import Sidebar from './components/Sidebar';
import { Icon, SparkleLoader, Toast, AINeuralLoader, ReleaseNotesModal, FontSizeController } from './components/UI';
import { generateAnalysis, generateOcrContent } from './services/geminiService';
import { STANDARDS_DATA, INITIAL_EVIDENCE, APP_VERSION } from './constants';
import { Standard, AuditInfo, AnalysisResult, FindingsViewMode, StandardsData } from './types';
import { fileToBase64, cleanAndParseJSON } from './utils';

const App = () => {
    // --- State: Layout & Config ---
    const [sidebarOpen, setSidebarOpen] = useState(true);
    const [sidebarWidth, setSidebarWidth] = useState(300);
    const [fontSizeScale, setFontSizeScale] = useState(1);
    const [showReleaseNotes, setShowReleaseNotes] = useState(false);

    // --- State: Data ---
    const [standards, setStandards] = useState<StandardsData>(STANDARDS_DATA);
    const [currentStandardKey, setCurrentStandardKey] = useState(Object.keys(STANDARDS_DATA)[0]);
    const [auditInfo, setAuditInfo] = useState<AuditInfo>({
        company: '', smo: '', department: '', interviewee: '', auditor: '', type: 'Internal'
    });
    const [selectedClauses, setSelectedClauses] = useState<string[]>([]);

    // --- State: Evidence & Analysis ---
    const [evidence, setEvidence] = useState(INITIAL_EVIDENCE);
    const [evidenceLanguage, setEvidenceLanguage] = useState<'en'|'vi'>('en');
    const [pastedImages, setPastedImages] = useState<File[]>([]);

    // --- State: UI Flags ---
    const [isOcrLoading, setIsOcrLoading] = useState(false);
    const [isAnalyzeLoading, setIsAnalyzeLoading] = useState(false);
    const [isEvidenceExportLoading, setIsEvidenceExportLoading] = useState(false);
    const [toastMessage, setToastMessage] = useState<string | null>(null);
    const [analysisResults, setAnalysisResults] = useState<AnalysisResult[]>([]);

    // --- Computed ---
    const isReadyForAnalysis = selectedClauses.length > 0 && evidence.trim().length > 10;

    const getAnalyzeTooltip = () => {
        if (selectedClauses.length === 0) return "Select at least one clause";
        if (evidence.trim().length <= 10) return "Enter more evidence";
        return "Start AI Analysis";
    };

    // --- Handlers ---

    const handlePaste = useCallback((e: React.ClipboardEvent) => {
        if (e.clipboardData.files.length > 0) {
            const files = Array.from(e.clipboardData.files).filter(f => f.type.startsWith('image/'));
            if (files.length > 0) {
                e.preventDefault();
                setPastedImages(prev => [...prev, ...files]);
                setToastMessage(`Added ${files.length} image(s) from clipboard`);
            }
        }
    }, []);

    const handleRemoveImage = (index: number) => {
        setPastedImages(prev => prev.filter((_, i) => i !== index));
    };

    const handleOcrUpload = async () => {
        if (pastedImages.length === 0) return;
        setIsOcrLoading(true);
        try {
            let combinedText = "";
            for (const file of pastedImages) {
                const base64 = await fileToBase64(file);
                const text = await generateOcrContent("Extract text from this audit evidence image.", base64, file.type);
                combinedText += `\n[Image Extracted]: ${text}\n`;
            }
            setEvidence(prev => prev + combinedText);
            setPastedImages([]);
            setToastMessage("Text extracted from images successfully");
        } catch (error) {
            console.error(error);
            setToastMessage("Failed to extract text from images");
        } finally {
            setIsOcrLoading(false);
        }
    };

    const handleAnalyze = async () => {
        if (!isReadyForAnalysis) return;
        setIsAnalyzeLoading(true);
        try {
            const prompt = `Analyze this evidence against clauses: ${selectedClauses.join(', ')}. Evidence: ${evidence}`;
            const resultJson = await generateAnalysis(prompt, "You are an ISO auditor.");
            const results = cleanAndParseJSON(resultJson);
            if (results) {
                setAnalysisResults(results);
                setToastMessage("Analysis Complete");
            } else {
                 setToastMessage("Analysis failed to produce structured data");
            }
        } catch (error) {
            console.error(error);
            setToastMessage("Analysis Error");
        } finally {
            setIsAnalyzeLoading(false);
        }
    };

    const handleExport = async (content: string, type: string, lang: string) => {
        setIsEvidenceExportLoading(true);
        // Simulate export delay
        await new Promise(r => setTimeout(r, 1000)); 
        setToastMessage(`Exported ${type} in ${lang.toUpperCase()}`);
        setIsEvidenceExportLoading(false);
    };

    const adjustFontSize = (dir: 'increase' | 'decrease') => {
        setFontSizeScale(prev => dir === 'increase' ? Math.min(prev + 0.1, 1.5) : Math.max(prev - 0.1, 0.8));
    };

    // --- Render ---
    return (
        <div className="flex h-screen w-full bg-white dark:bg-slate-950 text-slate-900 dark:text-slate-100 overflow-hidden font-sans transition-colors duration-300"
             style={{ fontSize: `${fontSizeScale}rem` }}>

            <Sidebar 
                isOpen={sidebarOpen}
                width={sidebarWidth}
                setWidth={setSidebarWidth}
                standards={standards}
                standardKey={currentStandardKey}
                setStandardKey={setCurrentStandardKey}
                auditInfo={auditInfo}
                setAuditInfo={setAuditInfo}
                selectedClauses={selectedClauses}
                setSelectedClauses={setSelectedClauses}
                onAddNewStandard={() => {
                     const id = `CUSTOM_${Date.now()}`;
                     setStandards(prev => ({...prev, [id]: { name: "New Standard", description: "Custom Standard", groups: [] }}));
                     setCurrentStandardKey(id);
                }}
                onUpdateStandard={(std: Standard) => {
                    setStandards(prev => ({...prev, [currentStandardKey]: std}));
                }}
                onResetStandard={(key: string) => {
                     setStandards(prev => {
                        const copy = {...prev};
                        if (STANDARDS_DATA[key]) copy[key] = STANDARDS_DATA[key];
                        return copy;
                     });
                }}
            />

            <div className="flex-1 flex flex-col min-w-0 h-full relative">
                 {/* Header */}
                 <header className="flex items-center justify-between px-6 py-4 border-b border-gray-100 dark:border-slate-800 bg-white/80 dark:bg-slate-900/80 backdrop-blur-md z-20">
                    <div className="flex items-center gap-4">
                        <button onClick={() => setSidebarOpen(!sidebarOpen)} className="p-2 rounded-xl hover:bg-gray-100 dark:hover:bg-slate-800 text-slate-500 transition-colors">
                            <Icon name="LayoutList" size={20} />
                        </button>
                        <h1 className="text-lg font-black tracking-tight flex items-center gap-2">
                             <span className="text-transparent bg-clip-text bg-gradient-to-r from-indigo-500 to-cyan-500">ISO Audit Pro</span>
                             <span className="text-[10px] bg-slate-100 dark:bg-slate-800 px-2 py-0.5 rounded-full text-slate-500 font-mono">v{APP_VERSION}</span>
                        </h1>
                    </div>
                    <div className="flex items-center gap-3">
                         <FontSizeController fontSizeScale={fontSizeScale} adjustFontSize={adjustFontSize} />
                         <button onClick={() => setShowReleaseNotes(true)} className="p-2 rounded-xl hover:bg-gray-100 dark:hover:bg-slate-800 text-slate-500 transition-colors">
                            <Icon name="Info" size={20} />
                         </button>
                    </div>
                 </header>

                 {/* Main Content */}
                 <main className="flex-1 overflow-y-auto p-6 relative">
                    <div className="max-w-5xl mx-auto space-y-6">

                        {/* Evidence Section */}
                        <div className="bg-white dark:bg-slate-900 rounded-3xl p-6 shadow-sm border border-gray-100 dark:border-slate-800 relative group">
                             <div className="flex justify-between items-center mb-4">
                                 <h3 className="text-sm font-bold uppercase tracking-widest text-slate-500 flex items-center gap-2">
                                     <Icon name="FileText" size={16}/> Evidence Collection
                                 </h3>
                                 <span className="text-xs text-slate-400">Paste text or images (Ctrl+V)</span>
                             </div>

                             <textarea 
                                value={evidence}
                                onChange={e => setEvidence(e.target.value)}
                                onPaste={handlePaste}
                                className="w-full h-64 bg-gray-50 dark:bg-slate-950 border border-gray-200 dark:border-slate-800 rounded-2xl p-4 text-sm font-mono leading-relaxed outline-none focus:border-indigo-500 transition-all resize-y"
                                placeholder="Paste interview notes, document excerpts, or images here..."
                             />

                            {pastedImages.length > 0 && (
                                <div className="flex-shrink-0 p-3 bg-gray-50 dark:bg-slate-900 border border-gray-200 dark:border-slate-800 rounded-2xl animate-in slide-in-from-bottom-5 duration-300 mt-4">
                                    <div className="flex justify-between items-center mb-2 px-1">
                                        <h4 className="text-xs font-bold text-slate-500 uppercase tracking-widest flex items-center gap-2">
                                            <Icon name="UploadCloud" size={14} className="text-indigo-500"/>
                                            Pending Extraction ({pastedImages.length})
                                        </h4>
                                        <button onClick={() => setPastedImages([])} className="text-xs text-red-500 hover:text-red-600 font-bold">Clear All</button>
                                    </div>
                                    <div className="flex gap-3 overflow-x-auto custom-scrollbar pb-2">
                                        {pastedImages.map((file, idx) => (
                                            <div key={idx} className="relative group flex-shrink-0 w-24 h-24 bg-white dark:bg-slate-800 rounded-xl shadow-sm border border-gray-100 dark:border-slate-700 overflow-hidden transition-transform duration-300 hover:scale-105">
                                                <img src={URL.createObjectURL(file)} alt="preview" className="w-full h-full object-cover opacity-80 group-hover:opacity-100 transition-opacity" />
                                                <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center">
                                                    <button onClick={() => handleRemoveImage(idx)} className="bg-red-500 hover:bg-red-600 text-white rounded-full p-1.5 shadow-lg transform scale-90 hover:scale-110 transition-all duration-200" title="Remove File"><Icon name="X" size={14}/></button>
                                                </div>
                                                <div className="absolute bottom-0 inset-x-0 bg-black/60 p-1 text-[8px] text-white truncate text-center">{file.name}</div>
                                            </div>
                                        ))}
                                        <div className="flex-shrink-0 w-24 h-24 flex items-center justify-center">
                                            <button onClick={handleOcrUpload} disabled={isOcrLoading} className="w-full h-full bg-indigo-600 hover:bg-indigo-700 text-white rounded-xl shadow-lg shadow-indigo-500/30 flex flex-col items-center justify-center gap-2 transition-all active:scale-95 disabled:opacity-50 hover:scale-105 duration-300">
                                                {isOcrLoading ? <Icon name="Loader" className="animate-spin" size={24}/> : <Icon name="ScanText" size={24}/>}
                                                <span className="text-[10px] font-bold">Extract All</span>
                                            </button>
                                        </div>
                                    </div>
                                </div>
                            )}

                             <div className="flex flex-row justify-end gap-2 mt-4 items-center">
                                <button onClick={handleAnalyze} disabled={!isReadyForAnalysis} title={getAnalyzeTooltip()} className={`h-10 px-6 rounded-xl font-bold transition-all duration-300 flex items-center justify-center gap-3 ${isReadyForAnalysis ? "bg-indigo-600 text-white shadow-xl shadow-indigo-500/30 hover:scale-105 active:scale-95 hover:bg-indigo-700" : "bg-gray-200 dark:bg-slate-800 text-slate-400 dark:text-slate-600 opacity-70 cursor-not-allowed border border-transparent"}`}>
                                    {isAnalyzeLoading ? <SparkleLoader className="text-white"/> : <Icon name="Wand2" size={18}/>}
                                    <span className="hidden md:inline text-xs uppercase tracking-wider">Compliance Analysis</span>
                                </button>

                                <button onClick={() => handleExport(evidence, 'evidence', evidenceLanguage)} className="h-10 px-4 bg-white dark:bg-slate-800 border border-gray-200 dark:border-slate-700 hover:border-indigo-500 text-slate-700 dark:text-slate-200 rounded-xl text-xs font-bold flex items-center gap-2 transition-all duration-300 hover:scale-105 active:scale-95 shadow-sm" title="Export Raw Text">
                                    {isEvidenceExportLoading ? <Icon name="Loader" className="animate-spin"/> : <Icon name="Download"/>} 
                                    <div className="flex items-center gap-1 ml-1 bg-gray-100 dark:bg-slate-700 rounded p-0.5">
                                        <span onClick={(e) => {e.stopPropagation(); setEvidenceLanguage('en');}} className={`px-1.5 rounded cursor-pointer ${evidenceLanguage === 'en' ? 'bg-white dark:bg-slate-600 shadow-sm text-indigo-600' : 'text-slate-400 hover:text-slate-600'}`}>EN</span>
                                        <span onClick={(e) => {e.stopPropagation(); setEvidenceLanguage('vi');}} className={`px-1.5 rounded cursor-pointer ${evidenceLanguage === 'vi' ? 'bg-white dark:bg-slate-600 shadow-sm text-indigo-600' : 'text-slate-400 hover:text-slate-600'}`}>VI</span>
                                    </div>
                                </button>
                            </div>
                        </div>

                        {analysisResults.length > 0 && (
                            <div className="animate-in fade-in slide-in-from-bottom-10">
                                <h3 className="text-lg font-bold mb-4">Audit Findings</h3>
                                <div className="grid gap-4">
                                    {analysisResults.map((res, i) => (
                                        <div key={i} className="p-4 bg-white dark:bg-slate-900 rounded-2xl border border-gray-100 dark:border-slate-800">
                                            <div className="flex justify-between">
                                                <span className="font-bold">{res.clauseId}</span>
                                                <span className={`px-2 py-0.5 rounded text-xs ${res.status === 'COMPLIANT' ? 'bg-green-100 text-green-700' : 'bg-red-100 text-red-700'}`}>{res.status}</span>
                                            </div>
                                            <p className="text-sm mt-2">{res.reason}</p>
                                        </div>
                                    ))}
                                </div>
                            </div>
                        )}

                    </div>
                 </main>
            </div>

            <ReleaseNotesModal isOpen={showReleaseNotes} onClose={() => setShowReleaseNotes(false)} />
            {isAnalyzeLoading && <AINeuralLoader message="Analyzing Compliance..." />}
            {toastMessage && <Toast message={toastMessage} onClose={() => setToastMessage(null)} />}
        </div>
    );
};

