        }
    };

    const handleExport = async (content: string, type: string, lang: string) => {
        setIsEvidenceExportLoading(true);
        // Simulate export delay
        await new Promise(r => setTimeout(r, 1000)); 
        setToastMessage(`Exported ${type} in ${lang.toUpperCase()}`);
        setIsEvidenceExportLoading(false);
    };

    const adjustFontSize = (dir: 'increase' | 'decrease') => {
        setFontSizeScale(prev => dir === 'increase' ? Math.min(prev + 0.1, 1.5) : Math.max(prev - 0.1, 0.8));
    };

    // --- Render ---
    return (
        <div className="flex h-screen w-full bg-white dark:bg-slate-950 text-slate-900 dark:text-slate-100 overflow-hidden font-sans transition-colors duration-300"
             style={{ fontSize: `${fontSizeScale}rem` }}>

            <Sidebar 
                isOpen={sidebarOpen}
                width={sidebarWidth}
                setWidth={setSidebarWidth}
                standards={standards}
                standardKey={currentStandardKey}
                setStandardKey={setCurrentStandardKey}
                auditInfo={auditInfo}
                setAuditInfo={setAuditInfo}
                selectedClauses={selectedClauses}
                setSelectedClauses={setSelectedClauses}
                onAddNewStandard={() => {
                     const id = `CUSTOM_${Date.now()}`;
                     setStandards(prev => ({...prev, [id]: { name: "New Standard", description: "Custom Standard", groups: [] }}));
                     setCurrentStandardKey(id);
                }}
                onUpdateStandard={(std: Standard) => {
                    setStandards(prev => ({...prev, [currentStandardKey]: std}));
                }}
                onResetStandard={(key: string) => {
                     setStandards(prev => {
                        const copy = {...prev};
                        if (STANDARDS_DATA[key]) copy[key] = STANDARDS_DATA[key];
                        return copy;
                     });
                }}
            />

            <div className="flex-1 flex flex-col min-w-0 h-full relative">
                 {/* Header */}
                 <header className="flex items-center justify-between px-6 py-4 border-b border-gray-100 dark:border-slate-800 bg-white/80 dark:bg-slate-900/80 backdrop-blur-md z-20">
                    <div className="flex items-center gap-4">
                        <button onClick={() => setSidebarOpen(!sidebarOpen)} className="p-2 rounded-xl hover:bg-gray-100 dark:hover:bg-slate-800 text-slate-500 transition-colors">
                            <Icon name="LayoutList" size={20} />
                        </button>
                        <h1 className="text-lg font-black tracking-tight flex items-center gap-2">
                             <span className="text-transparent bg-clip-text bg-gradient-to-r from-indigo-500 to-cyan-500">ISO Audit Pro</span>
                             <span className="text-[10px] bg-slate-100 dark:bg-slate-800 px-2 py-0.5 rounded-full text-slate-500 font-mono">v{APP_VERSION}</span>
                        </h1>
                    </div>
                    <div className="flex items-center gap-3">
                         <FontSizeController fontSizeScale={fontSizeScale} adjustFontSize={adjustFontSize} />
                         <button onClick={() => setShowReleaseNotes(true)} className="p-2 rounded-xl hover:bg-gray-100 dark:hover:bg-slate-800 text-slate-500 transition-colors">
                            <Icon name="Info" size={20} />
                         </button>
                    </div>
                 </header>

                 {/* Main Content */}
                 <main className="flex-1 overflow-y-auto p-6 relative">
                    <div className="max-w-5xl mx-auto space-y-6">

                        {/* Evidence Section */}
                        <div className="bg-white dark:bg-slate-900 rounded-3xl p-6 shadow-sm border border-gray-100 dark:border-slate-800 relative group">
                             <div className="flex justify-between items-center mb-4">
                                 <h3 className="text-sm font-bold uppercase tracking-widest text-slate-500 flex items-center gap-2">
                                     <Icon name="FileText" size={16}/> Evidence Collection
                                 </h3>
                                 <span className="text-xs text-slate-400">Paste text or images (Ctrl+V)</span>
                             </div>

                             <textarea 
                                value={evidence}
                                onChange={e => setEvidence(e.target.value)}
                                onPaste={handlePaste}
                                className="w-full h-64 bg-gray-50 dark:bg-slate-950 border border-gray-200 dark:border-slate-800 rounded-2xl p-4 text-sm font-mono leading-relaxed outline-none focus:border-indigo-500 transition-all resize-y"
                                placeholder="Paste interview notes, document excerpts, or images here..."
                             />

                            {pastedImages.length > 0 && (
                                <div className="flex-shrink-0 p-3 bg-gray-50 dark:bg-slate-900 border border-gray-200 dark:border-slate-800 rounded-2xl animate-in slide-in-from-bottom-5 duration-300 mt-4">
                                    <div className="flex justify-between items-center mb-2 px-1">
                                        <h4 className="text-xs font-bold text-slate-500 uppercase tracking-widest flex items-center gap-2">
                                            <Icon name="UploadCloud" size={14} className="text-indigo-500"/>
                                            Pending Extraction ({pastedImages.length})
                                        </h4>
                                        <button onClick={() => setPastedImages([])} className="text-xs text-red-500 hover:text-red-600 font-bold">Clear All</button>
                                    </div>
                                    <div className="flex gap-3 overflow-x-auto custom-scrollbar pb-2">
                                        {pastedImages.map((file, idx) => (
                                            <div key={idx} className="relative group flex-shrink-0 w-24 h-24 bg-white dark:bg-slate-800 rounded-xl shadow-sm border border-gray-100 dark:border-slate-700 overflow-hidden transition-transform duration-300 hover:scale-105">
                                                <img src={URL.createObjectURL(file)} alt="preview" className="w-full h-full object-cover opacity-80 group-hover:opacity-100 transition-opacity" />
                                                <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center">
                                                    <button onClick={() => handleRemoveImage(idx)} className="bg-red-500 hover:bg-red-600 text-white rounded-full p-1.5 shadow-lg transform scale-90 hover:scale-110 transition-all duration-200" title="Remove File"><Icon name="X" size={14}/></button>
                                                </div>
                                                <div className="absolute bottom-0 inset-x-0 bg-black/60 p-1 text-[8px] text-white truncate text-center">{file.name}</div>
                                            </div>
                                        ))}
                                        <div className="flex-shrink-0 w-24 h-24 flex items-center justify-center">
                                            <button onClick={handleOcrUpload} disabled={isOcrLoading} className="w-full h-full bg-indigo-600 hover:bg-indigo-700 text-white rounded-xl shadow-lg shadow-indigo-500/30 flex flex-col items-center justify-center gap-2 transition-all active:scale-95 disabled:opacity-50 hover:scale-105 duration-300">
                                                {isOcrLoading ? <Icon name="Loader" className="animate-spin" size={24}/> : <Icon name="ScanText" size={24}/>}
                                                <span className="text-[10px] font-bold">Extract All</span>
                                            </button>
                                        </div>
                                    </div>
                                </div>
                            )}

                             <div className="flex flex-row justify-end gap-2 mt-4 items-center">
                                <button onClick={handleAnalyze} disabled={!isReadyForAnalysis} title={getAnalyzeTooltip()} className={`h-10 px-6 rounded-xl font-bold transition-all duration-300 flex items-center justify-center gap-3 ${isReadyForAnalysis ? "bg-indigo-600 text-white shadow-xl shadow-indigo-500/30 hover:scale-105 active:scale-95 hover:bg-indigo-700" : "bg-gray-200 dark:bg-slate-800 text-slate-400 dark:text-slate-600 opacity-70 cursor-not-allowed border border-transparent"}`}>
                                    {isAnalyzeLoading ? <SparkleLoader className="text-white"/> : <Icon name="Wand2" size={18}/>}
                                    <span className="hidden md:inline text-xs uppercase tracking-wider">Compliance Analysis</span>
                                </button>

                                <button onClick={() => handleExport(evidence, 'evidence', evidenceLanguage)} className="h-10 px-4 bg-white dark:bg-slate-800 border border-gray-200 dark:border-slate-700 hover:border-indigo-500 text-slate-700 dark:text-slate-200 rounded-xl text-xs font-bold flex items-center gap-2 transition-all duration-300 hover:scale-105 active:scale-95 shadow-sm" title="Export Raw Text">
                                    {isEvidenceExportLoading ? <Icon name="Loader" className="animate-spin"/> : <Icon name="Download"/>} 
                                    <div className="flex items-center gap-1 ml-1 bg-gray-100 dark:bg-slate-700 rounded p-0.5">
                                        <span onClick={(e) => {e.stopPropagation(); setEvidenceLanguage('en');}} className={`px-1.5 rounded cursor-pointer ${evidenceLanguage === 'en' ? 'bg-white dark:bg-slate-600 shadow-sm text-indigo-600' : 'text-slate-400 hover:text-slate-600'}`}>EN</span>
                                        <span onClick={(e) => {e.stopPropagation(); setEvidenceLanguage('vi');}} className={`px-1.5 rounded cursor-pointer ${evidenceLanguage === 'vi' ? 'bg-white dark:bg-slate-600 shadow-sm text-indigo-600' : 'text-slate-400 hover:text-slate-600'}`}>VI</span>
                                    </div>
                                </button>
                            </div>
                        </div>

                        {analysisResults.length > 0 && (
                            <div className="animate-in fade-in slide-in-from-bottom-10">
                                <h3 className="text-lg font-bold mb-4">Audit Findings</h3>
                                <div className="grid gap-4">
                                    {analysisResults.map((res, i) => (
                                        <div key={i} className="p-4 bg-white dark:bg-slate-900 rounded-2xl border border-gray-100 dark:border-slate-800">
                                            <div className="flex justify-between">
                                                <span className="font-bold">{res.clauseId}</span>
                                                <span className={`px-2 py-0.5 rounded text-xs ${res.status === 'COMPLIANT' ? 'bg-green-100 text-green-700' : 'bg-red-100 text-red-700'}`}>{res.status}</span>
                                            </div>
                                            <p className="text-sm mt-2">{res.reason}</p>
                                        </div>
                                    ))}
                                </div>
                            </div>
                        )}

                    </div>
                 </main>
            </div>

            <ReleaseNotesModal isOpen={showReleaseNotes} onClose={() => setShowReleaseNotes(false)} />
            {isAnalyzeLoading && <AINeuralLoader message="Analyzing Compliance..." />}
            {toastMessage && <Toast message={toastMessage} onClose={() => setToastMessage(null)} />}
        </div>
    );
};

export default App;

import React, { useState, useEffect } from 'react';
import Sidebar from './components/Sidebar';
import ReleaseNotesModal from './components/ReleaseNotesModal';
import { 
    Icon, 
    Modal, 
    FontSizeController, 
    SparkleLoader, 
    AINeuralLoader, 
    Toast, 
    CommandPaletteModal, 
    SnowOverlay 
} from './components/UI';
import { 
    validateApiKey, 
    generateAnalysis, 
    generateOcrContent 
} from './services/geminiService';
import { 
    STANDARDS_DATA, 
    INITIAL_EVIDENCE, 
    APP_VERSION 
} from './constants';
import { 
    AuditInfo, 
    Standard, 
    StandardsData, 
    ApiKeyProfile,
    AnalysisResult,
    Clause
} from './types';
import { 
    fileToBase64, 
    cleanAndParseJSON 
} from './utils';

// Helper to save file
const saveFile = (content: string, filename: string, type: string = 'text/plain') => {
    const blob = new Blob([content], { type });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = filename;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
};

export default function App() {
    // --- State ---
    const [darkMode, setDarkMode] = useState(false);
    const [fontSizeScale, setFontSizeScale] = useState(1);

    // Sidebar
    const [sidebarOpen, setSidebarOpen] = useState(true);
    const [sidebarWidth, setSidebarWidth] = useState(300);

    // Data
    const [standards, setStandards] = useState<StandardsData>(STANDARDS_DATA);
    const [standardKey, setStandardKey] = useState<string>("ISO 9001:2015");
    const [auditInfo, setAuditInfo] = useState<AuditInfo>({
        company: "", smo: "", department: "", interviewee: "", auditor: "", type: "Internal"
    });
    const [selectedClauses, setSelectedClauses] = useState<string[]>([]);

    // Evidence & Analysis
    const [evidence, setEvidence] = useState(INITIAL_EVIDENCE);
    const [evidenceLanguage, setEvidenceLanguage] = useState<'en' | 'vi'>('en');
    const [analysisResults, setAnalysisResults] = useState<AnalysisResult[]>([]);

    // Loading States
    const [isAnalyzeLoading, setIsAnalyzeLoading] = useState(false);
    const [isEvidenceExportLoading, setIsEvidenceExportLoading] = useState(false);
    const [loadingMessage, setLoadingMessage] = useState("");

    // Modals
    const [showReleaseNotes, setShowReleaseNotes] = useState(false);
    const [showSettings, setShowSettings] = useState(false);
    const [showCommandPalette, setShowCommandPalette] = useState(false);
    const [toastMessage, setToastMessage] = useState<string | null>(null);

    // API Key
    const [apiKey, setApiKey] = useState("");
    const [apiKeyProfile, setApiKeyProfile] = useState<ApiKeyProfile | null>(null);

    // --- Effects ---
    useEffect(() => {
        // Init theme
        if (window.matchMedia && window.matchMedia('(prefers-color-scheme: dark)').matches) {
            setDarkMode(true);
        }
        // Load API Key
        const savedKey = localStorage.getItem("iso_api_key");
        if (savedKey) {
            setApiKey(savedKey);
            checkApiKey(savedKey);
        } else if (process.env.API_KEY) {
             setApiKey(process.env.API_KEY);
             checkApiKey(process.env.API_KEY);
        }
    }, []);

    useEffect(() => {
        if (darkMode) document.documentElement.classList.add('dark');
        else document.documentElement.classList.remove('dark');
    }, [darkMode]);

    useEffect(() => {
        document.documentElement.style.fontSize = `${16 * fontSizeScale}px`;
    }, [fontSizeScale]);

    useEffect(() => {
        const handleKeyDown = (e: KeyboardEvent) => {
            if ((e.metaKey || e.ctrlKey) && e.key === 'k') {
                e.preventDefault();
                setShowCommandPalette(true);
            }
        };
        window.addEventListener('keydown', handleKeyDown);
        return () => window.removeEventListener('keydown', handleKeyDown);
    }, []);

    // --- Handlers ---

    const checkApiKey = async (key: string) => {
        const result = await validateApiKey(key);
        setApiKeyProfile({
            id: 'default',
            label: 'Default Key',
            key: key,
            status: result.isValid ? 'valid' : result.errorType || 'invalid',
            latency: result.latency,
            lastChecked: new Date().toISOString()
        });
    };

    const handleSaveApiKey = (key: string) => {
        setApiKey(key);
        localStorage.setItem("iso_api_key", key);
        checkApiKey(key);
    };

    const handleAnalyze = async () => {
        if (!selectedClauses.length) {
            setToastMessage("Please select at least one clause.");
            return;
        }
        if (!evidence.trim()) {
            setToastMessage("Please provide evidence text.");
            return;
        }

        setIsAnalyzeLoading(true);
        setLoadingMessage("Analyzing compliance...");

        try {
            // Construct prompt
            const clauseTexts = selectedClauses.map(id => {
                // Helper to find clause deeply in standards structure
                const findClause = (groups: any[]): Clause | undefined => {
                     const search = (list: Clause[]): Clause | undefined => {
                         for(const c of list) {
                             if (c.id === id) return c;
                             if (c.subClauses) {
                                 const res = search(c.subClauses);
                                 if (res) return res;
                             }
                         }
                     }
                     for (const g of groups) {
                         const res = search(g.clauses);
                         if (res) return res;
                     }
                };
                const c = findClause(standards[standardKey].groups);
                return c ? `${c.code} ${c.title}: ${c.description}` : id;
            }).join("\n");

            const prompt = `Analyze the following evidence against these ISO clauses:\n\nCLAUSES:\n${clauseTexts}\n\nEVIDENCE:\n${evidence}\n\nProvide JSON output.`;
            const systemInstruction = "You are an expert ISO auditor.";

            const resultJson = await generateAnalysis(prompt, systemInstruction, apiKey);
            const parsed = cleanAndParseJSON(resultJson);

            if (parsed) {
                setAnalysisResults(parsed);
                setToastMessage("Analysis Complete");
            } else {
                setToastMessage("Analysis Failed to parse");
            }

        } catch (error: any) {
            setToastMessage("Error: " + error.message);
        } finally {
            setIsAnalyzeLoading(false);
            setLoadingMessage("");
        }
    };

    const handleExport = (content: string, type: 'evidence' | 'report', lang: 'en' | 'vi') => {
        setIsEvidenceExportLoading(true);
        // Simulate async
        setTimeout(() => {
            saveFile(content, `${type}_${lang}_${new Date().toISOString()}.txt`);
            setIsEvidenceExportLoading(false);
            setToastMessage("Exported successfully");
        }, 500);
    };

    const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
        if (e.target.files && e.target.files[0]) {
            const file = e.target.files[0];
            if (file.type.startsWith('image/')) {
                setLoadingMessage("OCR Processing...");
                setIsAnalyzeLoading(true); // Re-use loader
                try {
                    const base64 = await fileToBase64(file);
                    const text = await generateOcrContent("Extract text from this image for audit evidence.", base64, file.type, apiKey);
                    setEvidence(prev => prev + "\n\n[OCR]\n" + text);
                    setToastMessage("Image text extracted");
                } catch (err: any) {
                    setToastMessage("OCR Failed: " + err.message);
                } finally {
                    setIsAnalyzeLoading(false);
                    setLoadingMessage("");
                }
            } else {
                 // Text file
                 const text = await file.text();
                 setEvidence(prev => prev + "\n" + text);
            }
        }
    };

    // --- Helpers ---
    const isReadyForAnalysis = selectedClauses.length > 0 && evidence.length > 0 && apiKeyProfile?.status === 'valid';
    const getAnalyzeTooltip = () => {
        if (!apiKeyProfile || apiKeyProfile.status !== 'valid') return "API Key Invalid or Missing";
        if (selectedClauses.length === 0) return "Select clauses first";
        if (evidence.length === 0) return "Input evidence first";
        return "Start Analysis";
    };

    const adjustFontSize = (dir: 'increase' | 'decrease') => {
        setFontSizeScale(prev => dir === 'increase' ? Math.min(prev + 0.1, 1.5) : Math.max(prev - 0.1, 0.8));
    };

    // Standards Management Handlers (Passed to Sidebar)
    const handleUpdateStandard = (std: Standard) => {
        setStandards(prev => ({...prev, [standardKey]: std}));
    };

    const handleResetStandard = (key: string) => {
        setStandards(prev => ({...prev, [key]: STANDARDS_DATA[key]}));
    };

    const handleAddNewStandard = () => {
        const name = prompt("Enter new Standard Name:");
        if (name) {
            const newKey = name;
            setStandards(prev => ({...prev, [newKey]: { name, description: "New Standard", groups: [] }}));
            setStandardKey(newKey);
        }
    };

    return (
        <div className={`flex h-screen w-screen overflow-hidden bg-white dark:bg-slate-950 text-slate-800 dark:text-slate-200 font-sans transition-colors duration-300`}>
             <SnowOverlay />
             {isAnalyzeLoading && <AINeuralLoader message={loadingMessage} />}

             <Sidebar 
                isOpen={sidebarOpen}
                width={sidebarWidth}
                setWidth={setSidebarWidth}
                standards={standards}
                standardKey={standardKey}
                setStandardKey={setStandardKey}
                auditInfo={auditInfo}
                setAuditInfo={setAuditInfo}
                selectedClauses={selectedClauses}
                setSelectedClauses={setSelectedClauses}
                onAddNewStandard={handleAddNewStandard}
                onUpdateStandard={handleUpdateStandard}
                onResetStandard={handleResetStandard}
             />

             {/* Main Content */}
             <div className="flex-1 flex flex-col min-w-0 relative z-0">
                {/* Header */}
                <header className="h-16 border-b border-gray-100 dark:border-slate-800 flex items-center justify-between px-6 bg-white/80 dark:bg-slate-900/80 backdrop-blur-md z-20">
                    <div className="flex items-center gap-4">
                        <button onClick={() => setSidebarOpen(!sidebarOpen)} className="p-2 rounded-xl hover:bg-gray-100 dark:hover:bg-slate-800 text-slate-500 transition-colors">
                            <Icon name="Grid" size={20}/>
                        </button>
                        <h1 className="text-lg font-black tracking-tight bg-gradient-to-r from-indigo-500 to-purple-500 bg-clip-text text-transparent">
                            ISO Audit Pro <span className="text-[10px] text-slate-400 font-mono align-top ml-1">v{APP_VERSION}</span>
                        </h1>
                    </div>

                    <div className="flex items-center gap-3">
                         <div className={`flex items-center gap-2 px-3 py-1.5 rounded-full border ${apiKeyProfile?.status === 'valid' ? 'bg-emerald-50 border-emerald-200 text-emerald-700 dark:bg-emerald-900/20 dark:border-emerald-900' : 'bg-red-50 border-red-200 text-red-700'}`}>
                             <div className={`w-2 h-2 rounded-full ${apiKeyProfile?.status === 'valid' ? 'bg-emerald-500 animate-pulse' : 'bg-red-500'}`}></div>
                             <span className="text-xs font-bold uppercase tracking-wider">{apiKeyProfile?.status === 'valid' ? 'API Ready' : 'API Invalid'}</span>
                         </div>

                         <FontSizeController fontSizeScale={fontSizeScale} adjustFontSize={adjustFontSize} />

                         <button onClick={() => setDarkMode(!darkMode)} className="p-2 rounded-xl hover:bg-gray-100 dark:hover:bg-slate-800 transition-colors">
                            <Icon name={darkMode ? "Sun" : "Moon"} size={18}/>
                         </button>
                         <button onClick={() => setShowSettings(true)} className="p-2 rounded-xl hover:bg-gray-100 dark:hover:bg-slate-800 transition-colors">
                            <Icon name="Settings" size={18}/>
                         </button>
                         <button onClick={() => setShowReleaseNotes(true)} className="p-2 rounded-xl hover:bg-gray-100 dark:hover:bg-slate-800 transition-colors">
                            <Icon name="Info" size={18}/>
                         </button>
                    </div>
                </header>

                {/* Content Body */}
                <main className="flex-1 overflow-y-auto custom-scrollbar p-6">
                    <div className="max-w-5xl mx-auto space-y-6">

                        {/* Evidence Section */}
                        <div className="bg-white dark:bg-slate-900 rounded-2xl border border-gray-100 dark:border-slate-800 shadow-sm p-5 transition-all hover:shadow-md">
                            <div className="flex justify-between items-center mb-4">
                                <h3 className="text-sm font-black text-slate-800 dark:text-white uppercase tracking-wider flex items-center gap-2">
                                    <Icon name="FileText" className="text-indigo-500"/> Audit Evidence
                                </h3>
                                <div className="flex gap-2">
                                    <label className="cursor-pointer px-3 py-1.5 bg-gray-50 dark:bg-slate-800 hover:bg-indigo-50 dark:hover:bg-indigo-900/20 text-indigo-600 dark:text-indigo-400 rounded-lg text-xs font-bold border border-gray-200 dark:border-slate-700 transition-all flex items-center gap-2">
                                        <Icon name="UploadCloud" size={14}/> Upload File
                                        <input type="file" className="hidden" onChange={handleFileUpload} accept=".txt,.pdf,image/*" />
                                    </label>
                                </div>
                            </div>

                            <textarea 
                                className="w-full h-64 p-4 bg-gray-50 dark:bg-slate-950/50 border border-gray-200 dark:border-slate-700 rounded-xl text-sm font-mono text-slate-700 dark:text-slate-300 focus:ring-2 focus:ring-indigo-500/20 focus:border-indigo-500 outline-none resize-none transition-all placeholder-gray-400"
                                placeholder="Paste interview notes, observations, or document extracts here..."
                                value={evidence}
                                onChange={(e) => setEvidence(e.target.value)}
                            />

                            {/* MODIFIED: Buttons moved to bottom-right, equal height h-10, Analysis is to the LEFT of Export */}
                            <div className="flex flex-row justify-end gap-2 mt-4 items-center">
                                <button onClick={handleAnalyze} disabled={!isReadyForAnalysis} title={getAnalyzeTooltip()} className={`h-10 px-6 rounded-xl font-bold transition-all duration-300 flex items-center justify-center gap-3 ${isReadyForAnalysis ? "btn-shrimp shadow-xl hover:scale-105 active:scale-95" : "bg-gray-200 dark:bg-slate-800 text-slate-400 dark:text-slate-600 opacity-70 cursor-not-allowed border border-transparent"}`}>
                                    {isAnalyzeLoading ? <SparkleLoader className="text-white"/> : <Icon name="Wand2" size={18}/>}
                                    <span className="hidden md:inline text-xs uppercase tracking-wider">Compliance Analysis</span>
                                </button>

                                <button onClick={() => handleExport(evidence, 'evidence', evidenceLanguage)} className="h-10 px-4 bg-white dark:bg-slate-800 border border-gray-200 dark:border-slate-700 hover:border-indigo-500 text-slate-700 dark:text-slate-200 rounded-xl text-xs font-bold flex items-center gap-2 transition-all duration-300 hover:scale-105 active:scale-95 shadow-sm" title="Export Raw Text">
                                    {isEvidenceExportLoading ? <Icon name="Loader" className="animate-spin"/> : <Icon name="Download"/>} 
                                    <div className="lang-pill-container ml-1">
                                        <span onClick={(e) => {e.stopPropagation(); setEvidenceLanguage('en');}} className={`lang-pill-btn ${evidenceLanguage === 'en' ? 'lang-pill-active' : 'lang-pill-inactive'}`}>EN</span>
                                        <span onClick={(e) => {e.stopPropagation(); setEvidenceLanguage('vi');}} className={`lang-pill-btn ${evidenceLanguage === 'vi' ? 'lang-pill-active' : 'lang-pill-inactive'}`}>VI</span>
                                    </div>
                                </button>
                            </div>
                        </div>

                        {/* Analysis Results */}
                        {analysisResults.length > 0 && (
                             <div className="space-y-4 animate-in fade-in slide-in-from-bottom-10 duration-500">
                                <h3 className="text-sm font-black text-slate-800 dark:text-white uppercase tracking-wider flex items-center gap-2 px-1">
                                    <Icon name="CheckSquare" className="text-emerald-500"/> Audit Findings
                                </h3>
                                {analysisResults.map((result, idx) => (
                                    <div key={idx} className="bg-white dark:bg-slate-900 rounded-2xl border border-gray-100 dark:border-slate-800 p-5 shadow-sm hover:shadow-md transition-all">
                                        <div className="flex items-start justify-between mb-3">
                                            <div className="flex items-center gap-3">
                                                 <span className="bg-indigo-50 dark:bg-indigo-900/30 text-indigo-700 dark:text-indigo-400 font-black text-xs px-2 py-1 rounded">{result.clauseId}</span>
                                                 <span className={`text-xs font-bold px-2 py-1 rounded uppercase tracking-wider ${result.status === 'COMPLIANT' ? 'bg-emerald-100 text-emerald-700' : 'bg-red-100 text-red-700'}`}>{result.status}</span>
                                            </div>
                                        </div>
                                        <p className="text-sm font-bold text-slate-800 dark:text-slate-200 mb-2">{result.reason}</p>
                                        <div className="text-xs text-slate-500 dark:text-slate-400 space-y-2 bg-gray-50 dark:bg-slate-950 rounded-xl p-3">
                                            <p><strong className="text-indigo-500">Evidence:</strong> {result.evidence}</p>
                                            <p><strong className="text-indigo-500">Suggestion:</strong> {result.suggestion}</p>
                                            <p><strong className="text-indigo-500">Report Conclusion:</strong> {result.conclusion_report}</p>
                                        </div>
                                    </div>
                                ))}
                             </div>
                        )}
                    </div>
                </main>
             </div>

             {/* Modals */}
             <ReleaseNotesModal isOpen={showReleaseNotes} onClose={() => setShowReleaseNotes(false)} />

             <Modal isOpen={showSettings} title="Settings" onClose={() => setShowSettings(false)}>
                 <div className="space-y-4">
                     <div>
                         <label className="block text-xs font-bold text-slate-500 mb-2 uppercase">Google Gemini API Key</label>
                         <div className="relative">
                             <input 
                                type="password" 
                                className="w-full p-3 bg-gray-50 dark:bg-slate-800 border border-gray-200 dark:border-slate-700 rounded-xl text-sm outline-none focus:ring-2 focus:ring-indigo-500/20"
                                value={apiKey}
                                onChange={(e) => setApiKey(e.target.value)}
                                placeholder="sk-..."
                             />
                         </div>
                         <p className="text-[10px] text-slate-400 mt-2">Key is stored locally in your browser.</p>
                     </div>
                     <button onClick={() => handleSaveApiKey(apiKey)} className="w-full py-3 bg-indigo-600 hover:bg-indigo-700 text-white font-bold rounded-xl transition-colors">
                         Validate & Save Key
                     </button>
                 </div>
             </Modal>

             <CommandPaletteModal 
                isOpen={showCommandPalette} 
                onClose={() => setShowCommandPalette(false)} 
                actions={[
                    { label: "Start Analysis", icon: "Wand2", action: handleAnalyze },
                    { label: "Toggle Dark Mode", icon: "Moon", action: () => setDarkMode(!darkMode) }
                ]}
                onSelectAction={(a: any) => { a.action(); setShowCommandPalette(false); }}
             />

             {toastMessage && <Toast message={toastMessage} onClose={() => setToastMessage(null)} />}
        </div>
    );
}
